// ============================================================
// API Route: POST /api/auth/login
// Autentikasi berbasis Database (Prisma + bcrypt)
// ============================================================
import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import bcrypt from "bcryptjs";

export async function POST(req: NextRequest) {
  try {
    const { username, password, kelas, deviceId } = await req.json();

    if (!username || !password) {
      return NextResponse.json({ success: false, message: "Username dan password wajib diisi" }, { status: 400 });
    }

    const user = await prisma.user.findUnique({ where: { username } });

    if (!user) {
      return NextResponse.json({ success: false, message: "Username tidak ditemukan" }, { status: 401 });
    }

    // Blokir alumni
    if (user.role === "siswa" && user.isAlumni) {
      return NextResponse.json({ success: false, message: "Akses Ditolak: Akun alumni sudah tidak memiliki akses login." }, { status: 403 });
    }

    // Validasi kelas & device binding untuk siswa
    if (user.role === "siswa") {
      if (!kelas) return NextResponse.json({ success: false, message: "Harap pilih kelas Anda" }, { status: 400 });
      if (user.kelas !== kelas) return NextResponse.json({ success: false, message: "Kelas yang dipilih tidak sesuai data siswa" }, { status: 401 });

      // -- FITUR DEVICE BINDING DINONAKTIFKAN SEMENTARA UNTUK TESTING/DEMO SKRIPSI --
      /*
      if (deviceId) {
        if (user.deviceId && user.deviceId !== deviceId) {
          return NextResponse.json({
            success: false,
            message: "Akses Ditolak: Perangkat tidak dikenali. Akun Anda terikat ke perangkat lain. Hubungi Admin.",
          }, { status: 403 });
        }
        if (!user.deviceId) {
          await prisma.user.update({ where: { id: user.id }, data: { deviceId } });
        }
      }
      */
    }

    // Verifikasi password (bcrypt)
    const passwordMatch = await bcrypt.compare(password, user.password);
    if (!passwordMatch) {
      return NextResponse.json({ success: false, message: "Password salah" }, { status: 401 });
    }

    if (!user.isActive) {
      return NextResponse.json({ success: false, message: "Akun tidak aktif" }, { status: 403 });
    }

    // Catat Audit Log
    await prisma.auditLog.create({
      data: { userId: user.id, userName: user.name, role: user.role, action: "LOGIN" },
    });

    // Kembalikan data user tanpa password
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const { password: _, ...safeUser } = user;
    return NextResponse.json({ success: true, message: "Login berhasil", user: safeUser });

  } catch (error) {
    console.error("[API/auth/login]", error);
    return NextResponse.json({ success: false, message: "Terjadi kesalahan server" }, { status: 500 });
  }
}

"use client";
import { useStore } from "@/lib/store";
import { useState } from "react";
import { AuditAction } from "@/lib/types";
import { ShieldCheck, Search, Filter, Clock } from "lucide-react";
import { format } from "date-fns";
import { id as idLocale } from "date-fns/locale";

// Konfigurasi warna untuk setiap jenis aksi (AuditAction) agar mudah dibedakan secara visual
const ACTION_COLOR: Partial<Record<AuditAction, string>> = {
  LOGIN: "#10b981", LOGOUT: "#6366f1",
  TAMBAH_SISWA: "#3b82f6", EDIT_SISWA: "#f59e0b", HAPUS_SISWA: "#ef4444",
  TAMBAH_GURU: "#3b82f6", EDIT_GURU: "#f59e0b", HAPUS_GURU: "#ef4444",
  TAMBAH_KELAS: "#3b82f6", EDIT_KELAS: "#f59e0b", HAPUS_KELAS: "#ef4444",
  APPROVE_IZIN: "#10b981", REJECT_IZIN: "#ef4444",
  KIRIM_NOTIFIKASI: "#8b5cf6",
  ABSENSI_MASUK: "#10b981", ABSENSI_KELUAR: "#3b82f6",
  TAMBAH_PENGUMUMAN: "#f59e0b", HAPUS_PENGUMUMAN: "#ef4444",
  TAMBAH_EVENT: "#f97316", HAPUS_EVENT: "#ef4444",
  EDIT_PENGATURAN: "#94a3b8", EDIT_PROFIL: "#94a3b8",
};

const ROLE_COLOR: Record<string, string> = {
  admin: "#6366f1", guru: "#8b5cf6", siswa: "#10b981", wali: "#f59e0b",
};

// Komponen Halaman Audit Log (Dashboard Admin)
// Menampilkan rekam jejak aktivitas pengguna untuk tujuan pemantauan keamanan (monitoring)
export default function AdminAuditPage() {
  const { auditLogs } = useStore(); // Mengambil seluruh riwayat log dari state global
  const [search, setSearch] = useState("");
  const [filterRole, setFilterRole] = useState("all");
  const [filterAction, setFilterAction] = useState("all");

  // Memfilter log berdasarkan input pencarian teks, dropdown role, dan dropdown aksi
  const filtered = auditLogs.filter(log => {
    const matchSearch = search === "" ||
      log.userName.toLowerCase().includes(search.toLowerCase()) ||
      log.action.toLowerCase().includes(search.toLowerCase()) ||
      (log.target?.toLowerCase() ?? "").includes(search.toLowerCase());
    const matchRole = filterRole === "all" || log.role === filterRole;
    const matchAction = filterAction === "all" || log.action === filterAction;
    return matchSearch && matchRole && matchAction;
  }).sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

  const uniqueActions = [...new Set(auditLogs.map(l => l.action))];

  return (
    <div className="animate-fadeIn">
      <div style={{ marginBottom: 28 }}>
        <h1 style={{ fontSize: 26, fontWeight: 800, marginBottom: 4, display: "flex", alignItems: "center", gap: 10 }}>
          <ShieldCheck size={26} color="var(--accent-primary)" /> Audit Log Sistem
        </h1>
        <p style={{ color: "var(--text-muted)", fontSize: 14 }}>Rekam jejak seluruh aktivitas pengguna dalam sistem untuk keamanan dan akuntabilitas.</p>
      </div>

      {/* Stats */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(130px,1fr))", gap: 16, marginBottom: 24 }}>
        {[
          { label: "Total Log", value: auditLogs.length, color: "#6366f1" },
          { label: "Hari Ini", value: auditLogs.filter(l => l.timestamp.startsWith(new Date().toISOString().split("T")[0])).length, color: "#10b981" },
          { label: "Login", value: auditLogs.filter(l => l.action === "LOGIN").length, color: "#3b82f6" },
          { label: "Perubahan Data", value: auditLogs.filter(l => ["TAMBAH_SISWA","EDIT_SISWA","HAPUS_SISWA","TAMBAH_GURU","EDIT_GURU","HAPUS_GURU"].includes(l.action)).length, color: "#f59e0b" },
        ].map(s => (
          <div key={s.label} className="glass-card" style={{ padding: 20 }}>
            <div style={{ fontSize: 28, fontWeight: 800, color: s.color }}>{s.value}</div>
            <div style={{ fontSize: 12, color: "var(--text-muted)", marginTop: 4 }}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Filters */}
      <div style={{ display: "flex", gap: 10, marginBottom: 20, flexWrap: "wrap" }}>
        <div style={{ position: "relative", flex: 1, minWidth: 200 }}>
          <Search size={16} style={{ position: "absolute", left: 12, top: "50%", transform: "translateY(-50%)", color: "var(--text-muted)" }} />
          <input className="input-field" placeholder="Cari nama, aksi, target..." value={search}
            onChange={e => setSearch(e.target.value)} style={{ paddingLeft: 36 }} />
        </div>
        <select className="input-field" value={filterRole} onChange={e => setFilterRole(e.target.value)}
          style={{ width: "auto", colorScheme: "dark" }}>
          <option value="all">Semua Role</option>
          <option value="admin">Admin</option>
          <option value="guru">Guru</option>
          <option value="siswa">Siswa</option>
          <option value="wali">Wali</option>
        </select>
        <select className="input-field" value={filterAction} onChange={e => setFilterAction(e.target.value)}
          style={{ width: "auto", colorScheme: "dark" }}>
          <option value="all">Semua Aksi</option>
          {uniqueActions.map(a => <option key={a} value={a}>{a.replace(/_/g, " ")}</option>)}
        </select>
      </div>

      {/* Log list */}
      <div className="glass-card" style={{ padding: 24 }}>
        <div style={{ fontSize: 14, color: "var(--text-muted)", marginBottom: 16 }}>
          Menampilkan {filtered.length} dari {auditLogs.length} log
        </div>
        {filtered.length === 0 ? (
          <div style={{ textAlign: "center", padding: "48px 0", color: "var(--text-muted)" }}>
            <ShieldCheck size={48} style={{ margin: "0 auto 12px", opacity: 0.3 }} />
            <div>Tidak ada log yang sesuai filter</div>
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
            {filtered.map(log => (
              <div key={log.id} style={{ display: "flex", alignItems: "flex-start", gap: 12, padding: "12px 0",
                borderBottom: "1px solid rgba(255,255,255,0.03)" }}>
                <div style={{ width: 8, height: 8, borderRadius: "50%", marginTop: 6, flexShrink: 0,
                  background: ACTION_COLOR[log.action] ?? "#94a3b8" }} />
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 2, flexWrap: "wrap" }}>
                    <span style={{ fontSize: 13, fontWeight: 600, color: "var(--text-primary)" }}>{log.userName}</span>
                    <span style={{ fontSize: 10, padding: "1px 7px", borderRadius: 10,
                      background: `${ROLE_COLOR[log.role]}18`, color: ROLE_COLOR[log.role] }}>
                      {log.role}
                    </span>
                    <span style={{ fontSize: 12, fontWeight: 600, padding: "2px 8px", borderRadius: 6,
                      background: `${ACTION_COLOR[log.action] ?? "#94a3b8"}15`,
                      color: ACTION_COLOR[log.action] ?? "#94a3b8" }}>
                      {log.action.replace(/_/g, " ")}
                    </span>
                    {log.target && <span style={{ fontSize: 12, color: "var(--text-secondary)" }}>{log.target}</span>}
                  </div>
                  {log.detail && <div style={{ fontSize: 12, color: "var(--text-muted)" }}>{log.detail}</div>}
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 11, color: "var(--text-muted)", flexShrink: 0 }}>
                  <Clock size={11} />
                  {format(new Date(log.timestamp), "dd MMM yyyy HH:mm", { locale: idLocale })}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";
import { useStore } from "@/lib/store";
import { useState, useEffect } from "react";
import { FileText, Search, CheckCircle, XCircle, Clock, Filter } from "lucide-react";
import { format } from "date-fns";
import { id as idLocale } from "date-fns/locale";

export default function AdminIzinPage() {
  const { permits, students, classes, updatePermit } = useStore();
  const [filterKelas, setFilterKelas] = useState("all");
  const [filterStatus, setFilterStatus] = useState("all");
  const [search, setSearch] = useState("");

  const [currentPage, setCurrentPage] = useState(1);
  const ITEMS_PER_PAGE = 20;

  const filtered = permits.filter(p => {
    const matchKelas = filterKelas === "all" || p.kelas === filterKelas;
    const matchStatus = filterStatus === "all" || p.status === filterStatus;
    const matchSearch = search === "" || p.studentName.toLowerCase().includes(search.toLowerCase());
    return matchKelas && matchStatus && matchSearch;
  }).sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());

  // Reset pagination when filters change
  // eslint-disable-next-line react-hooks/set-state-in-effect
  // eslint-disable-next-line react-hooks/set-state-in-effect
  useEffect(() => { setCurrentPage(1); }, [filterKelas, filterStatus, search]);

  const totalPages = Math.max(1, Math.ceil(filtered.length / ITEMS_PER_PAGE));
  const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
  const paginated = filtered.slice(startIndex, startIndex + ITEMS_PER_PAGE);

  const TYPE_COLOR: Record<string, string> = { izin: "#3b82f6", sakit: "#ef4444", dispensasi: "#8b5cf6" };
  const TYPE_LABEL: Record<string, string> = { izin: "Izin", sakit: "Sakit", dispensasi: "Dispensasi" };

  const stats = {
    total: permits.length,
    pending: permits.filter(p => p.status === "pending").length,
    approved: permits.filter(p => p.status === "approved").length,
    rejected: permits.filter(p => p.status === "rejected").length,
  };

  return (
    <div className="animate-fadeIn">
      <div style={{ marginBottom: 28 }}>
        <h1 style={{ fontSize: 26, fontWeight: 800, marginBottom: 4 }}>Rekap Izin & Dispensasi</h1>
        <p style={{ color: "var(--text-muted)", fontSize: 14 }}>Pantau semua permohonan izin dari seluruh kelas.</p>
      </div>

      {/* Stats */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(130px,1fr))", gap: 16, marginBottom: 24 }}>
        {[
          { label: "Total", value: stats.total, color: "#6366f1", type: "primary" },
          { label: "Pending", value: stats.pending, color: "#f59e0b", type: "warning" },
          { label: "Disetujui", value: stats.approved, color: "#10b981", type: "success" },
          { label: "Ditolak", value: stats.rejected, color: "#ef4444", type: "danger" },
        ].map(s => (
          <div key={s.label} className={`stat-card ${s.type}`}>
            <div style={{ fontSize: 32, fontWeight: 800, color: s.color }}>{s.value}</div>
            <div style={{ fontSize: 12, color: "var(--text-muted)", marginTop: 4 }}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Filters */}
      <div style={{ display: "flex", gap: 10, marginBottom: 20, flexWrap: "wrap", alignItems: "center" }}>
        <div style={{ position: "relative", flex: 1, minWidth: 200 }}>
          <Search size={16} style={{ position: "absolute", left: 12, top: "50%", transform: "translateY(-50%)", color: "var(--text-muted)" }} />
          <input className="input-field" placeholder="Cari nama siswa..." value={search}
            onChange={e => setSearch(e.target.value)} style={{ paddingLeft: 36 }} />
        </div>
        <select className="input-field" value={filterKelas} onChange={e => setFilterKelas(e.target.value)}
          style={{ width: "auto", colorScheme: "dark" }}>
          <option value="all">Semua Kelas</option>
          {classes.map(k => <option key={k} value={k}>{k}</option>)}
        </select>
        <select className="input-field" value={filterStatus} onChange={e => setFilterStatus(e.target.value)}
          style={{ width: "auto", colorScheme: "dark" }}>
          <option value="all">Semua Status</option>
          <option value="pending">Pending</option>
          <option value="approved">Disetujui</option>
          <option value="rejected">Ditolak</option>
        </select>
      </div>

      {/* Table */}
      <div className="glass-card" style={{ padding: 24 }}>
        {filtered.length === 0 ? (
          <div style={{ textAlign: "center", padding: "48px 0", color: "var(--text-muted)" }}>
            <FileText size={48} style={{ margin: "0 auto 12px", opacity: 0.3 }} />
            <div>Tidak ada data sesuai filter</div>
          </div>
        ) : (
          <div>
            <div style={{ overflowX: "auto" }}>
              <table className="data-table">
                <thead>
                  <tr>
                    <th>Siswa</th>
                    <th>Kelas</th>
                    <th>Jenis</th>
                    <th>Tanggal</th>
                    <th>Alasan</th>
                    <th>Status</th>
                    <th>Pengajuan</th>
                    <th>Aksi</th>
                  </tr>
                </thead>
                <tbody>
                  {paginated.map(p => (
                    <tr key={p.id}>
                      <td style={{ fontWeight: 500, color: "var(--text-primary)" }}>{p.studentName}</td>
                      <td>{p.kelas}</td>
                      <td>
                        <span style={{ fontSize: 12, padding: "2px 8px", borderRadius: 10,
                          background: `${TYPE_COLOR[p.type]}15`, color: TYPE_COLOR[p.type] }}>
                          {TYPE_LABEL[p.type]}
                        </span>
                      </td>
                      <td style={{ fontSize: 12 }}>
                        {format(new Date(p.startDate), "dd MMM yyyy")}
                        {p.startDate !== p.endDate && <><br />{format(new Date(p.endDate), "dd MMM yyyy")}</>}
                      </td>
                      <td style={{ maxWidth: 200 }}>
                        <div style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }} title={p.reason}>
                          {p.reason}
                        </div>
                      </td>
                      <td>
                        {p.status === "approved" && (
                          <div style={{ display: "flex", alignItems: "center", gap: 4, color: "#10b981", fontSize: 13 }}>
                            <CheckCircle size={14} /> Disetujui
                          </div>
                        )}
                        {p.status === "rejected" && (
                          <div style={{ display: "flex", alignItems: "center", gap: 4, color: "#ef4444", fontSize: 13 }}>
                            <XCircle size={14} /> Ditolak
                          </div>
                        )}
                        {p.status === "pending" && (
                          <div style={{ display: "flex", alignItems: "center", gap: 4, color: "#f59e0b", fontSize: 13 }}>
                            <Clock size={14} /> Pending
                          </div>
                        )}
                      </td>
                      <td style={{ fontSize: 12, color: "var(--text-muted)" }}>
                        {format(new Date(p.createdAt), "dd MMM yyyy", { locale: idLocale })}
                      </td>
                      <td>
                        <div style={{ display: "flex", gap: 6 }}>
                          {p.status === "pending" ? (
                            <>
                              <button onClick={() => updatePermit(p.id, { status: "approved" })}
                                style={{ background: "rgba(16,185,129,0.1)", border: "none", color: "#10b981", padding: "4px 8px", borderRadius: 6, cursor: "pointer", fontSize: 12, fontWeight: 600 }}>
                                Setuju
                              </button>
                              <button onClick={() => updatePermit(p.id, { status: "rejected" })}
                                style={{ background: "rgba(239,68,68,0.1)", border: "none", color: "#ef4444", padding: "4px 8px", borderRadius: 6, cursor: "pointer", fontSize: 12, fontWeight: 600 }}>
                                Tolak
                              </button>
                            </>
                          ) : (
                            <button onClick={() => updatePermit(p.id, { status: "pending" })}
                              style={{ background: "var(--bg-secondary)", border: "1px solid var(--border-glass)", color: "var(--text-secondary)", padding: "4px 8px", borderRadius: 6, cursor: "pointer", fontSize: 12, fontWeight: 500 }}>
                              Undo
                            </button>
                          )}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            {/* Pagination Controls */}
            {totalPages > 1 && (
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "16px 20px", borderTop: "1px solid var(--border-glass)", flexWrap: "wrap", gap: 16 }}>
                <div style={{ fontSize: 13, color: "var(--text-muted)" }}>
                  Menampilkan {startIndex + 1} - {Math.min(startIndex + ITEMS_PER_PAGE, filtered.length)} dari {filtered.length}
                </div>
                <div style={{ display: "flex", gap: 6 }}>
                  <button onClick={() => setCurrentPage(Math.max(1, currentPage - 1))} disabled={currentPage === 1}
                    style={{ padding: "6px 12px", borderRadius: 6, background: "var(--bg-secondary)", border: "1px solid var(--border-glass)", cursor: currentPage === 1 ? "not-allowed" : "pointer", opacity: currentPage === 1 ? 0.5 : 1, color: "var(--text-primary)" }}>
                    Prev
                  </button>
                  <span style={{ padding: "6px 12px", fontSize: 13, display: "flex", alignItems: "center" }}>
                    Hal {currentPage} / {totalPages}
                  </span>
                  <button onClick={() => setCurrentPage(Math.min(totalPages, currentPage + 1))} disabled={currentPage === totalPages}
                    style={{ padding: "6px 12px", borderRadius: 6, background: "var(--bg-secondary)", border: "1px solid var(--border-glass)", cursor: currentPage === totalPages ? "not-allowed" : "pointer", opacity: currentPage === totalPages ? 0.5 : 1, color: "var(--text-primary)" }}>
                    Next
                  </button>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";
import { useStore } from "@/lib/store";
import { useState } from "react";
import { Calendar, Plus, Trash2, ChevronLeft, ChevronRight, Edit2 } from "lucide-react";
import { AcademicEvent, EventType } from "@/lib/types";
import Toast, { ToastType } from "@/components/Toast";
import { format, addMonths, subMonths, startOfMonth, endOfMonth, eachDayOfInterval, isSameMonth, isToday, isSameDay } from "date-fns";
import { id as idLocale } from "date-fns/locale";
import { v4 as uuidv4 } from "uuid";

const EVENT_CONFIG: Record<EventType, { label: string; color: string; bg: string }> = {
  libur_nasional: { label: "Libur Nasional", color: "#ef4444", bg: "rgba(239,68,68,0.15)" },
  libur_sekolah:  { label: "Libur Sekolah",  color: "#f97316", bg: "rgba(249,115,22,0.15)" },
  ujian:          { label: "Ujian",           color: "#8b5cf6", bg: "rgba(139,92,246,0.15)" },
  kegiatan:       { label: "Kegiatan",        color: "#3b82f6", bg: "rgba(59,130,246,0.15)" },
  rapat:          { label: "Rapat",           color: "#10b981", bg: "rgba(16,185,129,0.15)" },
};

export default function AdminKalenderPage() {
  const { events, addEvent, updateEvent, deleteEvent, currentUser } = useStore();
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [showForm, setShowForm] = useState(false);
  const [selectedDay, setSelectedDay] = useState<Date | null>(null);
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);
  const [form, setForm] = useState({
    id: "",
    title: "",
    startDate: "",
    endDate: "",
    type: "kegiatan" as EventType,
    description: "",
  });

  const monthStart = startOfMonth(currentMonth);
  const monthEnd = endOfMonth(currentMonth);
  const calDays = eachDayOfInterval({ start: monthStart, end: monthEnd });

  // Pad start
  const startPad = monthStart.getDay();
  const paddedDays = [
    ...Array(startPad).fill(null),
    ...calDays,
  ];

  const getEventsForDay = (day: Date) =>
    events.filter(e => {
      const start = new Date(e.startDate);
      const end = new Date(e.endDate);
      const d = new Date(day.toISOString().split("T")[0]);
      return d >= new Date(e.startDate) && d <= new Date(e.endDate);
    });

  const handleEdit = (ev: AcademicEvent) => {
    setForm({
      id: ev.id,
      title: ev.title,
      startDate: ev.startDate,
      endDate: ev.endDate,
      type: ev.type,
      description: ev.description || "",
    });
    setShowForm(true);
  };

  const handleSubmit = () => {
    if (!form.title.trim() || !form.startDate) {
      setToast({ message: "Judul dan tanggal wajib diisi", type: "error" });
      return;
    }

    if (form.id) {
      updateEvent(form.id, {
        title: form.title,
        startDate: form.startDate,
        endDate: form.endDate || form.startDate,
        type: form.type,
        description: form.description,
      });
      setToast({ message: "Event berhasil diperbarui!", type: "success" });
    } else {
      const event: AcademicEvent = {
        id: uuidv4(),
        title: form.title,
        startDate: form.startDate,
        endDate: form.endDate || form.startDate,
        type: form.type,
        description: form.description,
        createdBy: currentUser?.id ?? "admin-001",
      };
      addEvent(event);
      setToast({ message: "Event berhasil ditambahkan!", type: "success" });
    }

    setShowForm(false);
    setForm({ id: "", title: "", startDate: "", endDate: "", type: "kegiatan", description: "" });
  };

  const sortedEvents = [...events].sort((a, b) => a.startDate.localeCompare(b.startDate));

  return (
    <div className="animate-fadeIn">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 28, flexWrap: "wrap", gap: 16 }}>
        <div>
          <h1 style={{ fontSize: 26, fontWeight: 800, marginBottom: 4 }}>Kalender Akademik</h1>
          <p style={{ color: "var(--text-muted)", fontSize: 14 }}>Kelola jadwal, ujian, libur, dan kegiatan sekolah.</p>
        </div>
        <button className="btn-primary" onClick={() => { setForm({ id: "", title: "", startDate: "", endDate: "", type: "kegiatan", description: "" }); setShowForm(true); }} id="btn-tambah-event">
          <Plus size={16} /> Tambah Event
        </button>
      </div>

      <div className="calendar-layout">
        {/* Calendar */}
        <div className="glass-card" style={{ padding: 24 }}>
          {/* Month nav */}
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
            <button onClick={() => setCurrentMonth(subMonths(currentMonth, 1))}
              style={{ background: "var(--bg-glass)", border: "1px solid var(--border-glass)", borderRadius: 8, padding: "6px 10px", cursor: "pointer", color: "var(--text-primary)" }}>
              <ChevronLeft size={18} />
            </button>
            <div style={{ fontSize: 17, fontWeight: 700 }}>
              {format(currentMonth, "MMMM yyyy", { locale: idLocale })}
            </div>
            <button onClick={() => setCurrentMonth(addMonths(currentMonth, 1))}
              style={{ background: "var(--bg-glass)", border: "1px solid var(--border-glass)", borderRadius: 8, padding: "6px 10px", cursor: "pointer", color: "var(--text-primary)" }}>
              <ChevronRight size={18} />
            </button>
          </div>

          <div style={{ overflowX: "auto", paddingBottom: 8 }}>
            <div style={{ minWidth: 500 }}>
              {/* Day headers */}
              <div style={{ display: "grid", gridTemplateColumns: "repeat(7,minmax(0,1fr))", gap: 4, marginBottom: 8 }}>
                {["Min", "Sen", "Sel", "Rab", "Kam", "Jum", "Sab"].map(d => (
                  <div key={d} style={{ textAlign: "center", fontSize: 12, fontWeight: 600, color: "var(--text-muted)", padding: "4px 0" }}>{d}</div>
                ))}
              </div>

              {/* Calendar grid */}
              <div style={{ display: "grid", gridTemplateColumns: "repeat(7,minmax(0,1fr))", gap: 4 }}>
                {paddedDays.map((day, i) => {
                  if (!day) return <div key={`pad-${i}`} />;
                  const dayEvents = getEventsForDay(day);
                  const isCurrentDay = isToday(day);
                  return (
                    <div key={day.toISOString()}
                      onClick={() => setSelectedDay(day)}
                      style={{ minHeight: 64, padding: 6, borderRadius: 8, cursor: "pointer",
                        background: isCurrentDay ? "rgba(99,102,241,0.15)" : selectedDay && isSameDay(day, selectedDay) ? "var(--bg-glass)" : "transparent",
                        border: isCurrentDay ? "1px solid var(--accent-primary)" : "1px solid transparent",
                        transition: "all 0.15s" }}
                      onMouseEnter={e => { if (!isCurrentDay) e.currentTarget.style.background = "var(--bg-glass)"; }}
                      onMouseLeave={e => { if (!isCurrentDay && !(selectedDay && isSameDay(day, selectedDay))) e.currentTarget.style.background = "transparent"; }}>
                      <div style={{ fontSize: 13, fontWeight: isCurrentDay ? 800 : 500, color: isCurrentDay ? "var(--accent-primary)" : "var(--text-secondary)", marginBottom: 4 }}>
                        {day.getDate()}
                      </div>
                      <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
                        {dayEvents.slice(0, 2).map(ev => (
                          <div key={ev.id} style={{ fontSize: 9, fontWeight: 600, padding: "1px 4px", borderRadius: 3,
                            background: EVENT_CONFIG[ev.type].bg, color: EVENT_CONFIG[ev.type].color,
                            overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                            {ev.title}
                          </div>
                        ))}
                        {dayEvents.length > 2 && (
                          <div style={{ fontSize: 9, color: "var(--text-muted)" }}>+{dayEvents.length - 2} lagi</div>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Legend */}
          <div style={{ display: "flex", gap: 12, marginTop: 16, flexWrap: "wrap" }}>
            {Object.entries(EVENT_CONFIG).map(([key, cfg]) => (
              <div key={key} style={{ display: "flex", alignItems: "center", gap: 5, fontSize: 11 }}>
                <div style={{ width: 10, height: 10, borderRadius: 2, background: cfg.color }} />
                <span style={{ color: "var(--text-muted)" }}>{cfg.label}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Event list */}
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          {/* Selected day events */}
          {selectedDay && (
            <div className="glass-card" style={{ padding: 20 }}>
              <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 12, color: "var(--accent-primary)" }}>
                {format(selectedDay, "EEEE, dd MMMM", { locale: idLocale })}
              </div>
              {getEventsForDay(selectedDay).length === 0 ? (
                <div style={{ fontSize: 13, color: "var(--text-muted)", textAlign: "center", padding: "16px 0" }}>Tidak ada event</div>
              ) : (
                getEventsForDay(selectedDay).map(ev => (
                  <div key={ev.id} style={{ padding: "10px 12px", borderRadius: 8,
                    background: EVENT_CONFIG[ev.type].bg, marginBottom: 8 }}>
                    <div style={{ fontSize: 13, fontWeight: 600, color: EVENT_CONFIG[ev.type].color }}>{ev.title}</div>
                    {ev.description && <div style={{ fontSize: 12, color: "var(--text-muted)", marginTop: 2 }}>{ev.description}</div>}
                  </div>
                ))
              )}
            </div>
          )}

          {/* Upcoming events */}
          <div className="glass-card" style={{ padding: 20 }}>
            <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 16 }}>Semua Event</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {sortedEvents.map(ev => (
                <div key={ev.id} style={{ display: "flex", alignItems: "flex-start", gap: 10, padding: "10px 12px",
                  background: "var(--bg-glass)", borderRadius: 10, position: "relative" }}>
                  <div style={{ width: 4, alignSelf: "stretch", borderRadius: 2, background: EVENT_CONFIG[ev.type].color, flexShrink: 0 }} />
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: 13, fontWeight: 600, marginBottom: 2 }}>{ev.title}</div>
                    <div style={{ fontSize: 11, color: "var(--text-muted)" }}>
                      {format(new Date(ev.startDate), "dd MMM", { locale: idLocale })}
                      {ev.startDate !== ev.endDate && ` – ${format(new Date(ev.endDate), "dd MMM yyyy", { locale: idLocale })}`}
                    </div>
                    <span style={{ fontSize: 10, padding: "1px 6px", borderRadius: 10,
                      background: EVENT_CONFIG[ev.type].bg, color: EVENT_CONFIG[ev.type].color }}>
                      {EVENT_CONFIG[ev.type].label}
                    </span>
                  </div>
                  <div style={{ display: "flex", gap: 4 }}>
                    <button onClick={() => handleEdit(ev)}
                      style={{ background: "none", border: "none", cursor: "pointer", color: "var(--text-muted)", padding: 4, borderRadius: 4 }}
                      onMouseEnter={e => (e.currentTarget.style.color = "var(--accent-primary)")}
                      onMouseLeave={e => (e.currentTarget.style.color = "var(--text-muted)")}>
                      <Edit2 size={14} />
                    </button>
                    <button onClick={() => { deleteEvent(ev.id); setToast({ message: "Event dihapus", type: "info" }); }}
                      style={{ background: "none", border: "none", cursor: "pointer", color: "var(--text-muted)", padding: 4, borderRadius: 4 }}
                      onMouseEnter={e => (e.currentTarget.style.color = "#ef4444")}
                      onMouseLeave={e => (e.currentTarget.style.color = "var(--text-muted)")}>
                      <Trash2 size={14} />
                    </button>
                  </div>
                </div>
              ))}
              {sortedEvents.length === 0 && (
                <div style={{ textAlign: "center", color: "var(--text-muted)", fontSize: 13, padding: "16px 0" }}>Belum ada event</div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Add Event Modal */}
      {showForm && (
        <div className="modal-overlay" onClick={() => setShowForm(false)}>
          <div className="modal-box" onClick={e => e.stopPropagation()}>
            <h2 style={{ fontSize: 18, fontWeight: 700, marginBottom: 20, display: "flex", alignItems: "center", gap: 8 }}>
              <Calendar size={18} color="var(--accent-primary)" /> {form.id ? "Edit Event Kalender" : "Tambah Event Kalender"}
            </h2>
            <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
              <div>
                <label style={{ display: "block", fontSize: 13, marginBottom: 6, color: "var(--text-secondary)" }}>Judul Event</label>
                <input className="input-field" placeholder="Contoh: UAS Semester Genap" value={form.title}
                  onChange={e => setForm(f => ({ ...f, title: e.target.value }))} />
              </div>
              <div>
                <label style={{ display: "block", fontSize: 13, marginBottom: 6, color: "var(--text-secondary)" }}>Jenis Event</label>
                <select className="input-field" value={form.type} onChange={e => setForm(f => ({ ...f, type: e.target.value as EventType }))}
                  style={{ colorScheme: "dark" }}>
                  {Object.entries(EVENT_CONFIG).map(([key, cfg]) => (
                    <option key={key} value={key}>{cfg.label}</option>
                  ))}
                </select>
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
                <div>
                  <label style={{ display: "block", fontSize: 13, marginBottom: 6, color: "var(--text-secondary)" }}>Tanggal Mulai</label>
                  <input type="date" className="input-field" value={form.startDate}
                    onChange={e => setForm(f => ({ ...f, startDate: e.target.value }))} style={{ colorScheme: "dark" }} />
                </div>
                <div>
                  <label style={{ display: "block", fontSize: 13, marginBottom: 6, color: "var(--text-secondary)" }}>Tanggal Selesai</label>
                  <input type="date" className="input-field" value={form.endDate}
                    onChange={e => setForm(f => ({ ...f, endDate: e.target.value }))} style={{ colorScheme: "dark" }} />
                </div>
              </div>
              <div>
                <label style={{ display: "block", fontSize: 13, marginBottom: 6, color: "var(--text-secondary)" }}>Keterangan (opsional)</label>
                <textarea className="input-field" rows={3} value={form.description}
                  onChange={e => setForm(f => ({ ...f, description: e.target.value }))} style={{ resize: "none" }} />
              </div>
              <div style={{ display: "flex", gap: 12, justifyContent: "flex-end" }}>
                <button className="btn-secondary" onClick={() => setShowForm(false)}>Batal</button>
                <button className="btn-primary" onClick={handleSubmit} id="btn-simpan-event">Simpan Event</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";
import { useStore } from "@/lib/store";
import { useEffect, useState } from "react";
import { Bell, CheckCircle, AlertTriangle, MessageCircle, Mail, Send } from "lucide-react";
import { DUMMY_PARENTS, DUMMY_STUDENTS } from "@/lib/data";
import {
  buildAbsentMessage, buildWhatsAppUrl,
  createNotificationLog, sendPushNotification
} from "@/lib/notifications";
import Toast, { ToastType } from "@/components/Toast";
import { format } from "date-fns";
import { id as idLocale } from "date-fns/locale";

interface ToastState { message: string; type: ToastType }

export default function AdminNotifPage() {
  const { students, records, notifications, addNotification } = useStore();
  const [toast, setToast]   = useState<ToastState | null>(null);
  const [sending, setSending] = useState<string | null>(null);
  const [mounted, setMounted] = useState(false);


  // eslint-disable-next-line react-hooks/set-state-in-effect
  // eslint-disable-next-line react-hooks/set-state-in-effect
  useEffect(() => setMounted(true), []);

  const today = new Date().toISOString().split("T")[0];
  const todayRecords = records.filter((r) => r.date === today);

  // Find absent students today
  const absentStudents = students.filter((s) => {
    const record = todayRecords.find((r) => r.studentId === s.id);
    return !record || record.status === "tidak_hadir";
  });

  const sendNotification = async (studentId: string, type: "push" | "whatsapp" | "email") => {
    setSending(`${studentId}-${type}`);
    const student = DUMMY_STUDENTS.find((s) => s.id === studentId);
    if (!student) return;
    const parent = DUMMY_PARENTS.find((p) => p.id === student.parentId);
    if (!parent) { setToast({ message: "Wali murid tidak ditemukan", type: "error" }); setSending(null); return; }

    const msg = buildAbsentMessage({ studentName: student.name, kelas: student.kelas,
      date: today, status: "tidak_hadir" });
    const attendanceId = `att-${studentId}-${today}`;

    if (type === "push") {
      await sendPushNotification("⚠️ Siswa Tidak Hadir", msg);
    } else if (type === "whatsapp") {
      if (parent.waNumber) {
        window.open(buildWhatsAppUrl(parent.waNumber, msg), "_blank");
      }
    } else {
      await fetch("/api/notifications/email", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ to: parent.email, studentName: student.name, kelas: student.kelas, date: today }),
      });
    }

    const logEntry = createNotificationLog(studentId, parent.id, type, msg, attendanceId, "sent");
    addNotification(logEntry);
    setToast({ message: `Notifikasi ${type} berhasil dikirim ke ${parent.name}`, type: "success" });
    setSending(null);
  };

  const sendAllNotifications = async () => {
    for (const s of absentStudents) {
      await sendNotification(s.id, "push");
      await new Promise((r) => setTimeout(r, 300));
    }
    setToast({ message: `${absentStudents.length} notifikasi berhasil dikirim!`, type: "success" });
  };

  if (!mounted) return null;

  return (
    <div className="animate-fadeIn">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 24, flexWrap: "wrap", gap: 16 }}>
        <div>
          <h1 style={{ fontSize: 24, fontWeight: 800 }}>Pusat Notifikasi</h1>
          <p style={{ color: "var(--text-muted)", fontSize: 14 }}>
            {format(new Date(), "EEEE, dd MMMM yyyy", { locale: idLocale })}
          </p>
        </div>
        {absentStudents.length > 0 && (
          <button onClick={sendAllNotifications} className="btn-primary">
            <Send size={15} /> Kirim Semua Notifikasi ({absentStudents.length})
          </button>
        )}
      </div>

      {/* Absent students */}
      <div className="glass-card" style={{ padding: 24, marginBottom: 24 }}>
        <div style={{ fontSize: 15, fontWeight: 700, marginBottom: 16, display: "flex", alignItems: "center", gap: 8 }}>
          <AlertTriangle size={18} color="#f59e0b" />
          Siswa Belum Absen Hari Ini ({absentStudents.length})
        </div>

        {absentStudents.length === 0 ? (
          <div style={{ textAlign: "center", padding: "32px 0", color: "#10b981" }}>
            <CheckCircle size={40} style={{ marginBottom: 10 }} />
            <div style={{ fontWeight: 600 }}>Semua siswa sudah absen hari ini 🎉</div>
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
            {absentStudents.map((s) => {
              const parent = DUMMY_PARENTS.find((p) => p.id === s.parentId);
              return (
                <div key={s.id} style={{ display: "flex", alignItems: "center", gap: 14,
                  padding: "14px 16px", background: "rgba(239,68,68,0.06)",
                  border: "1px solid rgba(239,68,68,0.15)", borderRadius: "var(--radius-md)",
                  flexWrap: "wrap" }}>
                  <div style={{ width: 38, height: 38, borderRadius: "50%",
                    background: "rgba(239,68,68,0.15)", display: "flex", alignItems: "center",
                    justifyContent: "center", fontSize: 15, fontWeight: 700, color: "#ef4444", flexShrink: 0 }}>
                    {s.name.charAt(0)}
                  </div>
                  <div style={{ flex: 1, minWidth: 140 }}>
                    <div style={{ fontWeight: 600, fontSize: 14 }}>{s.name}</div>
                    <div style={{ fontSize: 12, color: "var(--text-muted)" }}>
                      {s.kelas} • Wali: {parent?.name ?? "–"}
                    </div>
                  </div>
                  <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                    <button onClick={() => sendNotification(s.id, "push")}
                      disabled={sending === `${s.id}-push`}
                      style={{ background: "rgba(99,102,241,0.15)", border: "1px solid rgba(99,102,241,0.3)",
                        borderRadius: 8, padding: "6px 12px", cursor: "pointer", color: "#6366f1",
                        fontSize: 12, fontWeight: 600, display: "flex", alignItems: "center", gap: 6 }}>
                      <Bell size={12} /> Push
                    </button>
                    {parent?.waNumber && (
                      <button onClick={() => sendNotification(s.id, "whatsapp")}
                        style={{ background: "rgba(16,185,129,0.15)", border: "1px solid rgba(16,185,129,0.3)",
                          borderRadius: 8, padding: "6px 12px", cursor: "pointer", color: "#10b981",
                          fontSize: 12, fontWeight: 600, display: "flex", alignItems: "center", gap: 6 }}>
                        <MessageCircle size={12} /> WhatsApp
                      </button>
                    )}
                    <button onClick={() => sendNotification(s.id, "email")}
                      style={{ background: "rgba(59,130,246,0.15)", border: "1px solid rgba(59,130,246,0.3)",
                        borderRadius: 8, padding: "6px 12px", cursor: "pointer", color: "#3b82f6",
                        fontSize: 12, fontWeight: 600, display: "flex", alignItems: "center", gap: 6 }}>
                      <Mail size={12} /> Email
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Notification log */}
      <div className="glass-card" style={{ padding: 24 }}>
        <div style={{ fontSize: 15, fontWeight: 700, marginBottom: 16, display: "flex", alignItems: "center", gap: 8 }}>
          <Bell size={18} color="var(--accent-primary)" /> Log Notifikasi ({notifications.length})
        </div>
        {notifications.length === 0 ? (
          <div style={{ textAlign: "center", color: "var(--text-muted)", padding: "24px 0", fontSize: 14 }}>
            Belum ada notifikasi
          </div>
        ) : (
          <div style={{ overflowX: "auto" }}>
            <table className="data-table">
              <thead>
                <tr><th>Waktu</th><th>Pesan</th><th>Tipe</th><th>Status</th></tr>
              </thead>
              <tbody>
                {notifications.map((n) => (
                  <tr key={n.id}>
                    <td style={{ whiteSpace: "nowrap", fontSize: 12 }}>
                      {new Date(n.sentAt).toLocaleString("id-ID")}
                    </td>
                    <td style={{ fontSize: 12, maxWidth: 320 }}>{n.message}</td>
                    <td>
                      <span style={{ fontSize: 11, fontWeight: 600, textTransform: "capitalize",
                        padding: "2px 8px", borderRadius: 10,
                        background: n.type === "push" ? "rgba(99,102,241,0.15)"
                          : n.type === "whatsapp" ? "rgba(16,185,129,0.15)"
                          : "rgba(59,130,246,0.15)",
                        color: n.type === "push" ? "#6366f1"
                          : n.type === "whatsapp" ? "#10b981" : "#3b82f6" }}>
                        {n.type}
                      </span>
                    </td>
                    <td>
                      <span style={{ color: n.status === "sent" ? "#10b981" : "#ef4444", fontSize: 12, fontWeight: 600 }}>
                        {n.status === "sent" ? "✓ Terkirim" : "✗ Gagal"}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

