"use client";
import { useStore } from "@/lib/store";
import { useState } from "react";
import { FileText, CheckCircle, XCircle, Clock, Search, Filter } from "lucide-react";
import { PermitRequest } from "@/lib/types";
import Toast, { ToastType } from "@/components/Toast";
import { format } from "date-fns";
import { id as idLocale } from "date-fns/locale";
import { v4 as uuidv4 } from "uuid";

type FilterStatus = "all" | "pending" | "approved" | "rejected";

export default function GuruIzinPage() {
  const { currentUser, permits, updatePermit, addAttendance, addInAppNotification } = useStore();
  const [filterStatus, setFilterStatus] = useState<FilterStatus>("all");
  const [search, setSearch] = useState("");
  const [selected, setSelected] = useState<PermitRequest | null>(null);
  const [rejectReason, setRejectReason] = useState("");
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  if (!currentUser) return null;
  const teacher = currentUser as import("@/lib/types").Teacher;
  const myKelas = teacher.kelasWali || "";

  const myPermits = permits.filter(p =>
    p.kelas === myKelas &&
    (filterStatus === "all" || p.status === filterStatus) &&
    (search === "" || p.studentName.toLowerCase().includes(search.toLowerCase()) ||
      p.reason.toLowerCase().includes(search.toLowerCase()))
  ).sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());

  const handleApprove = (permit: PermitRequest) => {
    updatePermit(permit.id, {
      status: "approved",
      approvedBy: currentUser.id,
      approvedAt: new Date().toISOString(),
    });
    // Update attendance records for date range
    const start = new Date(permit.startDate);
    const end = new Date(permit.endDate);
    for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
      if (d.getDay() === 0 || d.getDay() === 6) continue;
      const ds = d.toISOString().split("T")[0];
      addAttendance({
        id: `att-${permit.studentId}-${ds}-${permit.type}`,
        studentId: permit.studentId,
        studentName: permit.studentName,
        kelas: permit.kelas,
        date: ds,
        status: permit.type === "sakit" ? "sakit" : "izin",
        notes: `${permit.type === "sakit" ? "Sakit" : permit.type === "dispensasi" ? "Dispensasi" : "Izin"}: ${permit.reason}`,
      });
    }
    // Notify student
    addInAppNotification({
      id: uuidv4(),
      userId: permit.studentId,
      title: "Izin Disetujui ✓",
      message: `Permohonan ${permit.type} Anda tanggal ${permit.startDate} telah disetujui oleh wali kelas.`,
      type: "success",
      isRead: false,
      link: "/dashboard/siswa/izin",
      createdAt: new Date().toISOString(),
    });
    setSelected(null);
    setToast({ message: "Permohonan izin disetujui!", type: "success" });
  };

  const handleReject = (permit: PermitRequest) => {
    if (!rejectReason.trim()) {
      setToast({ message: "Harap isi alasan penolakan", type: "error" });
      return;
    }
    updatePermit(permit.id, {
      status: "rejected",
      approvedBy: currentUser.id,
      approvedAt: new Date().toISOString(),
      rejectedReason: rejectReason,
    });
    addInAppNotification({
      id: uuidv4(),
      userId: permit.studentId,
      title: "Izin Ditolak",
      message: `Permohonan ${permit.type} Anda ditolak. Alasan: ${rejectReason}`,
      type: "danger",
      isRead: false,
      link: "/dashboard/siswa/izin",
      createdAt: new Date().toISOString(),
    });
    setSelected(null);
    setRejectReason("");
    setToast({ message: "Permohonan izin ditolak.", type: "info" });
  };

  const FILTER_TABS: { label: string; value: FilterStatus; color: string }[] = [
    { label: "Semua", value: "all", color: "#6366f1" },
    { label: "Pending", value: "pending", color: "#f59e0b" },
    { label: "Disetujui", value: "approved", color: "#10b981" },
    { label: "Ditolak", value: "rejected", color: "#ef4444" },
  ];

  const TYPE_COLOR: Record<string, string> = { izin: "#3b82f6", sakit: "#ef4444", dispensasi: "#8b5cf6" };
  const TYPE_LABEL: Record<string, string> = { izin: "Izin", sakit: "Sakit", dispensasi: "Dispensasi" };

  return (
    <div className="animate-fadeIn">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <div style={{ marginBottom: 28 }}>
        <h1 style={{ fontSize: 26, fontWeight: 800, marginBottom: 4 }}>Manajemen Izin Siswa</h1>
        <p style={{ color: "var(--text-muted)", fontSize: 14 }}>Kelas Wali: <strong style={{ color: "var(--text-primary)" }}>{myKelas || "–"}</strong></p>
      </div>

      {/* Stats */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(130px,1fr))", gap: 16, marginBottom: 24 }}>
        {[
          { label: "Total", value: permits.filter(p => p.kelas === myKelas).length, color: "#6366f1" },
          { label: "Pending", value: permits.filter(p => p.kelas === myKelas && p.status === "pending").length, color: "#f59e0b" },
          { label: "Disetujui", value: permits.filter(p => p.kelas === myKelas && p.status === "approved").length, color: "#10b981" },
          { label: "Ditolak", value: permits.filter(p => p.kelas === myKelas && p.status === "rejected").length, color: "#ef4444" },
        ].map(s => (
          <div key={s.label} className="glass-card" style={{ padding: 20 }}>
            <div style={{ fontSize: 28, fontWeight: 800, color: s.color }}>{s.value}</div>
            <div style={{ fontSize: 12, color: "var(--text-muted)", marginTop: 4 }}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Filters */}
      <div style={{ display: "flex", gap: 10, marginBottom: 20, flexWrap: "wrap", alignItems: "center" }}>
        <div style={{ position: "relative", flex: 1, minWidth: 200 }}>
          <Search size={16} style={{ position: "absolute", left: 12, top: "50%", transform: "translateY(-50%)", color: "var(--text-muted)" }} />
          <input className="input-field" placeholder="Cari nama/alasan..." value={search}
            onChange={e => setSearch(e.target.value)} style={{ paddingLeft: 36 }} />
        </div>
        <div style={{ display: "flex", gap: 6 }}>
          {FILTER_TABS.map(tab => (
            <button key={tab.value} onClick={() => setFilterStatus(tab.value)}
              style={{ padding: "8px 14px", borderRadius: 8, cursor: "pointer", fontSize: 13, fontWeight: 500,
                background: filterStatus === tab.value ? `${tab.color}20` : "var(--bg-glass)",
                color: filterStatus === tab.value ? tab.color : "var(--text-muted)",
                border: `1px solid ${filterStatus === tab.value ? tab.color + "40" : "var(--border-glass)"}` }}>
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      {/* List */}
      <div className="glass-card" style={{ padding: 24 }}>
        {myPermits.length === 0 ? (
          <div style={{ textAlign: "center", padding: "48px 0", color: "var(--text-muted)" }}>
            <FileText size={48} style={{ margin: "0 auto 12px", opacity: 0.3 }} />
            <div>Tidak ada data izin {filterStatus !== "all" ? `dengan status "${filterStatus}"` : ""}</div>
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
            {myPermits.map(p => (
              <div key={p.id} style={{ padding: 16, background: "var(--bg-glass)", borderRadius: 12, border: "1px solid var(--border-glass)",
                transition: "all 0.2s" }}
                onMouseEnter={e => (e.currentTarget.style.borderColor = "var(--border-glow)")}
                onMouseLeave={e => (e.currentTarget.style.borderColor = "var(--border-glass)")}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", flexWrap: "wrap", gap: 10 }}>
                  <div style={{ flex: 1 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8, flexWrap: "wrap" }}>
                      <span style={{ fontSize: 14, fontWeight: 600 }}>{p.studentName}</span>
                      <span style={{ fontSize: 12, padding: "2px 8px", borderRadius: 12,
                        background: `${TYPE_COLOR[p.type]}15`, color: TYPE_COLOR[p.type] }}>
                        {TYPE_LABEL[p.type]}
                      </span>
                      {p.status === "pending" && <span className="badge badge-warning">Menunggu</span>}
                      {p.status === "approved" && <span className="badge badge-success">Disetujui</span>}
                      {p.status === "rejected" && <span className="badge badge-danger">Ditolak</span>}
                    </div>
                    <div style={{ fontSize: 13, color: "var(--text-secondary)", marginBottom: 6 }}>{p.reason}</div>
                    <div style={{ fontSize: 12, color: "var(--text-muted)" }}>
                      📅 {format(new Date(p.startDate), "dd MMM yyyy", { locale: idLocale })}
                      {p.startDate !== p.endDate && ` – ${format(new Date(p.endDate), "dd MMM yyyy", { locale: idLocale })}`}
                    </div>
                    {p.status === "rejected" && p.rejectedReason && (
                      <div style={{ marginTop: 6, fontSize: 12, color: "#ef4444" }}>Alasan penolakan: {p.rejectedReason}</div>
                    )}
                  </div>
                  {p.status === "pending" && (
                    <button onClick={() => setSelected(p)} className="btn-primary" style={{ padding: "8px 16px", fontSize: 13 }} id={`btn-proses-${p.id}`}>
                      Proses
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Modal proses */}
      {selected && (
        <div className="modal-overlay" onClick={() => { setSelected(null); setRejectReason(""); }}>
          <div className="modal-box" onClick={e => e.stopPropagation()} style={{ maxWidth: 500 }}>
            <h2 style={{ fontSize: 18, fontWeight: 700, marginBottom: 16 }}>Proses Permohonan Izin</h2>
            <div style={{ padding: 16, background: "var(--bg-glass)", borderRadius: 10, marginBottom: 16 }}>
              <div style={{ fontWeight: 600, marginBottom: 4 }}>{selected.studentName}</div>
              <div style={{ fontSize: 13, color: "var(--text-secondary)", marginBottom: 8 }}>{selected.reason}</div>
              <div style={{ fontSize: 12, color: "var(--text-muted)" }}>
                {TYPE_LABEL[selected.type]} · {format(new Date(selected.startDate), "dd MMM yyyy")}
                {selected.startDate !== selected.endDate && ` – ${format(new Date(selected.endDate), "dd MMM yyyy")}`}
              </div>
            </div>
            <div style={{ marginBottom: 16 }}>
              <label style={{ display: "block", fontSize: 13, marginBottom: 6, color: "var(--text-secondary)" }}>Alasan penolakan (isi jika ditolak)</label>
              <textarea className="input-field" rows={3} value={rejectReason} onChange={e => setRejectReason(e.target.value)}
                placeholder="Contoh: Harap lampirkan surat keterangan dokter..." style={{ resize: "none" }} />
            </div>
            <div style={{ display: "flex", gap: 12 }}>
              <button onClick={() => { setSelected(null); setRejectReason(""); }} className="btn-secondary" style={{ flex: 1 }}>Batal</button>
              <button onClick={() => handleReject(selected)} className="btn-danger" style={{ flex: 1 }} id="btn-tolak-izin">
                <XCircle size={16} /> Tolak
              </button>
              <button onClick={() => handleApprove(selected)} className="btn-success" style={{ flex: 1 }} id="btn-setujui-izin">
                <CheckCircle size={16} /> Setujui
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";
import { useStore } from "@/lib/store";
import { useState } from "react";
import { Calendar, ChevronLeft, ChevronRight } from "lucide-react";
import { EventType } from "@/lib/types";
import { format, addMonths, subMonths, startOfMonth, endOfMonth, eachDayOfInterval, isSameMonth, isToday, isSameDay } from "date-fns";
import { id as idLocale } from "date-fns/locale";

const EVENT_CONFIG: Record<EventType, { label: string; color: string; bg: string }> = {
  libur_nasional: { label: "Libur Nasional", color: "#ef4444", bg: "rgba(239,68,68,0.15)" },
  libur_sekolah:  { label: "Libur Sekolah",  color: "#f97316", bg: "rgba(249,115,22,0.15)" },
  ujian:          { label: "Ujian",           color: "#8b5cf6", bg: "rgba(139,92,246,0.15)" },
  kegiatan:       { label: "Kegiatan",        color: "#3b82f6", bg: "rgba(59,130,246,0.15)" },
  rapat:          { label: "Rapat",           color: "#10b981", bg: "rgba(16,185,129,0.15)" },
};

export default function KalenderAkademikPage() {
  const { events } = useStore();
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [selectedDay, setSelectedDay] = useState<Date | null>(null);

  const monthStart = startOfMonth(currentMonth);
  const monthEnd = endOfMonth(currentMonth);
  const calDays = eachDayOfInterval({ start: monthStart, end: monthEnd });

  const startPad = monthStart.getDay();
  const paddedDays = [
    ...Array(startPad).fill(null),
    ...calDays,
  ];

  const getEventsForDay = (day: Date) =>
    events.filter(e => {
      const d = new Date(day.toISOString().split("T")[0]);
      return d >= new Date(e.startDate) && d <= new Date(e.endDate);
    });

  const sortedEvents = [...events].sort((a, b) => a.startDate.localeCompare(b.startDate));

  return (
    <div className="animate-fadeIn">
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 28, flexWrap: "wrap", gap: 16 }}>
        <div>
          <h1 style={{ fontSize: 26, fontWeight: 800, marginBottom: 4 }}>Kalender Akademik</h1>
          <p style={{ color: "var(--text-muted)", fontSize: 14 }}>Jadwal, ujian, libur, dan kegiatan sekolah.</p>
        </div>
      </div>

      <div className="calendar-layout">
        {/* Calendar */}
        <div className="glass-card" style={{ padding: 24 }}>
          {/* Month nav */}
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
            <button onClick={() => setCurrentMonth(subMonths(currentMonth, 1))}
              style={{ background: "var(--bg-glass)", border: "1px solid var(--border-glass)", borderRadius: 8, padding: "6px 10px", cursor: "pointer", color: "var(--text-primary)" }}>
              <ChevronLeft size={18} />
            </button>
            <div style={{ fontSize: 17, fontWeight: 700 }}>
              {format(currentMonth, "MMMM yyyy", { locale: idLocale })}
            </div>
            <button onClick={() => setCurrentMonth(addMonths(currentMonth, 1))}
              style={{ background: "var(--bg-glass)", border: "1px solid var(--border-glass)", borderRadius: 8, padding: "6px 10px", cursor: "pointer", color: "var(--text-primary)" }}>
              <ChevronRight size={18} />
            </button>
          </div>

          <div style={{ overflowX: "auto", paddingBottom: 8 }}>
            <div style={{ minWidth: 500 }}>
              {/* Day headers */}
              <div style={{ display: "grid", gridTemplateColumns: "repeat(7,minmax(0,1fr))", gap: 4, marginBottom: 8 }}>
                {["Min", "Sen", "Sel", "Rab", "Kam", "Jum", "Sab"].map(d => (
                  <div key={d} style={{ textAlign: "center", fontSize: 12, fontWeight: 600, color: "var(--text-muted)", padding: "4px 0" }}>{d}</div>
                ))}
              </div>

              {/* Calendar grid */}
              <div style={{ display: "grid", gridTemplateColumns: "repeat(7,minmax(0,1fr))", gap: 4 }}>
                {paddedDays.map((day, i) => {
                  if (!day) return <div key={`pad-${i}`} />;
                  const dayEvents = getEventsForDay(day);
                  const isCurrentDay = isToday(day);
                  return (
                    <div key={day.toISOString()}
                      onClick={() => setSelectedDay(day)}
                      style={{ minHeight: 64, padding: 6, borderRadius: 8, cursor: "pointer",
                        background: isCurrentDay ? "rgba(99,102,241,0.15)" : selectedDay && isSameDay(day, selectedDay) ? "var(--bg-glass)" : "transparent",
                        border: isCurrentDay ? "1px solid var(--accent-primary)" : "1px solid transparent",
                        transition: "all 0.15s" }}
                      onMouseEnter={e => { if (!isCurrentDay) e.currentTarget.style.background = "var(--bg-glass)"; }}
                      onMouseLeave={e => { if (!isCurrentDay && !(selectedDay && isSameDay(day, selectedDay))) e.currentTarget.style.background = "transparent"; }}>
                      <div style={{ fontSize: 13, fontWeight: isCurrentDay ? 800 : 500, color: isCurrentDay ? "var(--accent-primary)" : "var(--text-secondary)", marginBottom: 4 }}>
                        {day.getDate()}
                      </div>
                      <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
                        {dayEvents.slice(0, 2).map(ev => (
                          <div key={ev.id} style={{ fontSize: 9, fontWeight: 600, padding: "1px 4px", borderRadius: 3,
                            background: EVENT_CONFIG[ev.type].bg, color: EVENT_CONFIG[ev.type].color,
                            overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                            {ev.title}
                          </div>
                        ))}
                        {dayEvents.length > 2 && (
                          <div style={{ fontSize: 9, color: "var(--text-muted)" }}>+{dayEvents.length - 2} lagi</div>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Legend */}
          <div style={{ display: "flex", gap: 12, marginTop: 16, flexWrap: "wrap" }}>
            {Object.entries(EVENT_CONFIG).map(([key, cfg]) => (
              <div key={key} style={{ display: "flex", alignItems: "center", gap: 5, fontSize: 11 }}>
                <div style={{ width: 10, height: 10, borderRadius: 2, background: cfg.color }} />
                <span style={{ color: "var(--text-muted)" }}>{cfg.label}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Event list */}
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          {/* Selected day events */}
          {selectedDay && (
            <div className="glass-card" style={{ padding: 20 }}>
              <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 12, color: "var(--accent-primary)" }}>
                {format(selectedDay, "EEEE, dd MMMM", { locale: idLocale })}
              </div>
              {getEventsForDay(selectedDay).length === 0 ? (
                <div style={{ fontSize: 13, color: "var(--text-muted)", textAlign: "center", padding: "16px 0" }}>Tidak ada event</div>
              ) : (
                getEventsForDay(selectedDay).map(ev => (
                  <div key={ev.id} style={{ padding: "10px 12px", borderRadius: 8,
                    background: EVENT_CONFIG[ev.type].bg, marginBottom: 8 }}>
                    <div style={{ fontSize: 13, fontWeight: 600, color: EVENT_CONFIG[ev.type].color }}>{ev.title}</div>
                    {ev.description && <div style={{ fontSize: 12, color: "var(--text-muted)", marginTop: 2 }}>{ev.description}</div>}
                  </div>
                ))
              )}
            </div>
          )}

          {/* Upcoming events */}
          <div className="glass-card" style={{ padding: 20 }}>
            <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 16 }}>Semua Event</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {sortedEvents.map(ev => (
                <div key={ev.id} style={{ display: "flex", alignItems: "flex-start", gap: 10, padding: "10px 12px",
                  background: "var(--bg-glass)", borderRadius: 10, position: "relative" }}>
                  <div style={{ width: 4, alignSelf: "stretch", borderRadius: 2, background: EVENT_CONFIG[ev.type].color, flexShrink: 0 }} />
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: 13, fontWeight: 600, marginBottom: 2 }}>{ev.title}</div>
                    <div style={{ fontSize: 11, color: "var(--text-muted)" }}>
                      {format(new Date(ev.startDate), "dd MMM", { locale: idLocale })}
                      {ev.startDate !== ev.endDate && ` – ${format(new Date(ev.endDate), "dd MMM yyyy", { locale: idLocale })}`}
                    </div>
                    <span style={{ fontSize: 10, padding: "1px 6px", borderRadius: 10,
                      background: EVENT_CONFIG[ev.type].bg, color: EVENT_CONFIG[ev.type].color }}>
                      {EVENT_CONFIG[ev.type].label}
                    </span>
                  </div>
                </div>
              ))}
              {sortedEvents.length === 0 && (
                <div style={{ textAlign: "center", color: "var(--text-muted)", fontSize: 13, padding: "16px 0" }}>Belum ada event</div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";
import { useStore } from "@/lib/store";
import { useState } from "react";
import { BookOpen, Plus, Save, Users, ClipboardList, CheckCircle, XCircle } from "lucide-react";
import { SubjectAttendanceRecord } from "@/lib/types";
import Toast, { ToastType } from "@/components/Toast";
import { format } from "date-fns";
import { id as idLocale } from "date-fns/locale";
import { v4 as uuidv4 } from "uuid";

export default function GuruMapelPage() {
  const { currentUser, students, subjectRecords, addSubjectRecord, getSubjectRecordsByTeacher } = useStore();
  const [showForm, setShowForm] = useState(false);
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);
  const [form, setForm] = useState({
    subjectName: "",
    date: new Date().toISOString().split("T")[0],
    session: 1,
    presentStudentIds: [] as string[],
    notes: "",
  });

  if (!currentUser) return null;
  const teacher = currentUser as import("@/lib/types").Teacher;
  const myKelas = teacher.kelasWali || "";
  const myStudents = students.filter(s => s.kelas === myKelas);
  const mySubjects = teacher.mataPelajaran || [];
  const myRecords = getSubjectRecordsByTeacher(currentUser.id)
    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  const togglePresent = (studentId: string) => {
    setForm(f => ({
      ...f,
      presentStudentIds: f.presentStudentIds.includes(studentId)
        ? f.presentStudentIds.filter(id => id !== studentId)
        : [...f.presentStudentIds, studentId],
    }));
  };

  const handleSelectAll = () => {
    setForm(f => ({
      ...f,
      presentStudentIds: f.presentStudentIds.length === myStudents.length ? [] : myStudents.map(s => s.id),
    }));
  };

  const handleSubmit = () => {
    if (!form.subjectName) {
      setToast({ message: "Pilih mata pelajaran terlebih dahulu", type: "error" });
      return;
    }
    const record: SubjectAttendanceRecord = {
      id: uuidv4(),
      subjectName: form.subjectName,
      teacherId: currentUser.id,
      kelas: myKelas,
      date: form.date,
      session: form.session,
      presentStudentIds: form.presentStudentIds,
      absentStudentIds: myStudents.filter(s => !form.presentStudentIds.includes(s.id)).map(s => s.id),
      notes: form.notes,
      createdAt: new Date().toISOString(),
    };
    addSubjectRecord(record);
    setToast({ message: `Absensi ${form.subjectName} berhasil disimpan!`, type: "success" });
    setShowForm(false);
    setForm({ subjectName: "", date: new Date().toISOString().split("T")[0], session: 1, presentStudentIds: [], notes: "" });
  };

  // Summary per subject
  const subjectSummary = mySubjects.map(subj => {
    const recs = myRecords.filter(r => r.subjectName === subj);
    const totalSessions = recs.length;
    const avgPresent = totalSessions > 0
      ? Math.round(recs.reduce((s, r) => s + r.presentStudentIds.length, 0) / totalSessions)
      : 0;
    return { subjectName: subj, totalSessions, avgPresent };
  });

  return (
    <div className="animate-fadeIn">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 28, flexWrap: "wrap", gap: 16 }}>
        <div>
          <h1 style={{ fontSize: 26, fontWeight: 800, marginBottom: 4 }}>Absensi per Mata Pelajaran</h1>
          <p style={{ color: "var(--text-muted)", fontSize: 14 }}>Kelas: <strong style={{ color: "var(--text-primary)" }}>{myKelas}</strong> · Catat kehadiran per sesi pertemuan.</p>
        </div>
        <button className="btn-primary" onClick={() => setShowForm(true)} id="btn-catat-absensi-mapel">
          <Plus size={16} /> Catat Absensi
        </button>
      </div>

      {/* Subject summary cards */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(200px,1fr))", gap: 16, marginBottom: 24 }}>
        {subjectSummary.map(s => (
          <div key={s.subjectName} className="glass-card" style={{ padding: 20 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 12 }}>
              <div style={{ width: 36, height: 36, borderRadius: 10, background: "var(--gradient-primary)",
                display: "flex", alignItems: "center", justifyContent: "center" }}>
                <BookOpen size={18} color="white" />
              </div>
              <div style={{ fontSize: 14, fontWeight: 600 }}>{s.subjectName}</div>
            </div>
            <div style={{ display: "flex", gap: 16 }}>
              <div>
                <div style={{ fontSize: 22, fontWeight: 800, color: "#6366f1" }}>{s.totalSessions}</div>
                <div style={{ fontSize: 11, color: "var(--text-muted)" }}>Sesi</div>
              </div>
              <div>
                <div style={{ fontSize: 22, fontWeight: 800, color: "#10b981" }}>{s.avgPresent}</div>
                <div style={{ fontSize: 11, color: "var(--text-muted)" }}>Rata² Hadir</div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Records list */}
      <div className="glass-card" style={{ padding: 24 }}>
        <div style={{ fontSize: 15, fontWeight: 700, marginBottom: 16, display: "flex", alignItems: "center", gap: 8 }}>
          <ClipboardList size={18} color="var(--accent-primary)" /> Riwayat Absensi per Pertemuan
        </div>
        {myRecords.length === 0 ? (
          <div style={{ textAlign: "center", padding: "48px 0", color: "var(--text-muted)" }}>
            <BookOpen size={48} style={{ margin: "0 auto 12px", opacity: 0.3 }} />
            <div>Belum ada data absensi per mata pelajaran</div>
            <div style={{ fontSize: 13, marginTop: 8 }}>Klik "Catat Absensi" untuk memulai</div>
          </div>
        ) : (
          myRecords.map(rec => {
            const classStudents = students.filter(s => s.kelas === rec.kelas);
            const presentStudents = classStudents.filter(s => rec.presentStudentIds.includes(s.id));
            const absentStudents = classStudents.filter(s => rec.absentStudentIds.includes(s.id));
            const rate = classStudents.length > 0 ? Math.round((presentStudents.length / classStudents.length) * 100) : 0;
            return (
              <div key={rec.id} style={{ padding: 16, background: "var(--bg-glass)", borderRadius: 12, marginBottom: 12, border: "1px solid var(--border-glass)" }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", flexWrap: "wrap", gap: 10, marginBottom: 12 }}>
                  <div>
                    <div style={{ fontSize: 15, fontWeight: 700, marginBottom: 2 }}>{rec.subjectName}</div>
                    <div style={{ fontSize: 13, color: "var(--text-muted)" }}>
                      {format(new Date(rec.date), "EEEE, dd MMM yyyy", { locale: idLocale })} · Pertemuan ke-{rec.session}
                    </div>
                  </div>
                  <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <div style={{ textAlign: "right" }}>
                      <div style={{ fontSize: 22, fontWeight: 800, color: rate >= 75 ? "#10b981" : "#ef4444" }}>{rate}%</div>
                      <div style={{ fontSize: 11, color: "var(--text-muted)" }}>Kehadiran</div>
                    </div>
                  </div>
                </div>
                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
                  <div>
                    <div style={{ fontSize: 12, color: "#10b981", fontWeight: 600, marginBottom: 6, display: "flex", alignItems: "center", gap: 4 }}>
                      <CheckCircle size={12} /> Hadir ({presentStudents.length})
                    </div>
                    <div style={{ display: "flex", flexWrap: "wrap", gap: 4 }}>
                      {presentStudents.map(s => (
                        <span key={s.id} style={{ fontSize: 11, padding: "2px 8px", borderRadius: 10, background: "rgba(16,185,129,0.1)", color: "#10b981" }}>
                          {s.name}
                        </span>
                      ))}
                    </div>
                  </div>
                  <div>
                    <div style={{ fontSize: 12, color: "#ef4444", fontWeight: 600, marginBottom: 6, display: "flex", alignItems: "center", gap: 4 }}>
                      <XCircle size={12} /> Tidak Hadir ({absentStudents.length})
                    </div>
                    <div style={{ display: "flex", flexWrap: "wrap", gap: 4 }}>
                      {absentStudents.map(s => (
                        <span key={s.id} style={{ fontSize: 11, padding: "2px 8px", borderRadius: 10, background: "rgba(239,68,68,0.1)", color: "#ef4444" }}>
                          {s.name}
                        </span>
                      ))}
                    </div>
                  </div>
                </div>
                {rec.notes && <div style={{ marginTop: 8, fontSize: 12, color: "var(--text-muted)", fontStyle: "italic" }}>📝 {rec.notes}</div>}
              </div>
            );
          })
        )}
      </div>

      {/* Form Modal */}
      {showForm && (
        <div className="modal-overlay" onClick={() => setShowForm(false)}>
          <div className="modal-box" onClick={e => e.stopPropagation()} style={{ maxWidth: 540 }}>
            <h2 style={{ fontSize: 18, fontWeight: 700, marginBottom: 20, display: "flex", alignItems: "center", gap: 8 }}>
              <BookOpen size={18} color="var(--accent-primary)" /> Catat Absensi Mata Pelajaran
            </h2>
            <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
                <div>
                  <label style={{ display: "block", fontSize: 13, marginBottom: 6, color: "var(--text-secondary)" }}>Mata Pelajaran</label>
                  <select className="input-field" value={form.subjectName} onChange={e => setForm(f => ({ ...f, subjectName: e.target.value }))}
                    style={{ colorScheme: "dark" }}>
                    <option value="">Pilih mapel...</option>
                    {mySubjects.map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                </div>
                <div>
                  <label style={{ display: "block", fontSize: 13, marginBottom: 6, color: "var(--text-secondary)" }}>Kelas</label>
                  <select className="input-field" value={myKelas} onChange={() => {}} disabled title="Hanya kelas wali untuk versi mockup ini">
                    <option value={myKelas}>{myKelas}</option>
                  </select>
                </div>
                <div>
                  <label style={{ display: "block", fontSize: 13, marginBottom: 6, color: "var(--text-secondary)" }}>Pertemuan ke-</label>
                  <input type="number" className="input-field" min={1} value={form.session}
                    onChange={e => setForm(f => ({ ...f, session: Number(e.target.value) }))} />
                </div>
              </div>
              <div>
                <label style={{ display: "block", fontSize: 13, marginBottom: 6, color: "var(--text-secondary)" }}>Tanggal</label>
                <input type="date" className="input-field" value={form.date}
                  onChange={e => setForm(f => ({ ...f, date: e.target.value }))} style={{ colorScheme: "dark" }} />
              </div>
              <div>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
                  <label style={{ fontSize: 13, color: "var(--text-secondary)" }}>
                    Siswa Hadir ({form.presentStudentIds.length}/{myStudents.length})
                  </label>
                  <button onClick={handleSelectAll} style={{ fontSize: 12, background: "none", border: "none", cursor: "pointer", color: "var(--accent-primary)" }}>
                    {form.presentStudentIds.length === myStudents.length ? "Kosongkan" : "Pilih Semua"}
                  </button>
                </div>
                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 6, maxHeight: 200, overflowY: "auto" }}>
                  {myStudents.map(s => (
                    <label key={s.id} style={{ display: "flex", alignItems: "center", gap: 8, padding: "8px 10px",
                      borderRadius: 8, cursor: "pointer", fontSize: 13,
                      background: form.presentStudentIds.includes(s.id) ? "rgba(16,185,129,0.1)" : "var(--bg-glass)",
                      border: `1px solid ${form.presentStudentIds.includes(s.id) ? "rgba(16,185,129,0.3)" : "var(--border-glass)"}`,
                      transition: "all 0.15s" }}>
                      <input type="checkbox" checked={form.presentStudentIds.includes(s.id)}
                        onChange={() => togglePresent(s.id)} style={{ accentColor: "#10b981" }} />
                      <span style={{ color: form.presentStudentIds.includes(s.id) ? "#10b981" : "var(--text-secondary)" }}>{s.name}</span>
                    </label>
                  ))}
                </div>
              </div>
              <div>
                <label style={{ display: "block", fontSize: 13, marginBottom: 6, color: "var(--text-secondary)" }}>Catatan (opsional)</label>
                <textarea className="input-field" rows={2} value={form.notes}
                  onChange={e => setForm(f => ({ ...f, notes: e.target.value }))}
                  placeholder="Contoh: Siswa terlambat karena hujan..." style={{ resize: "none" }} />
              </div>
              <div style={{ display: "flex", gap: 12, justifyContent: "flex-end" }}>
                <button className="btn-secondary" onClick={() => setShowForm(false)}>Batal</button>
                <button className="btn-primary" onClick={handleSubmit} id="btn-simpan-absensi-mapel">
                  <Save size={16} /> Simpan Absensi
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";
import { useStore } from "@/lib/store";
import { DUMMY_STUDENTS } from "@/lib/data";
import { Bell, AlertTriangle } from "lucide-react";

export default function GuruNotifPage() {
  const { notifications, currentUser } = useStore();
  const teacher = currentUser as import("@/lib/types").Teacher;
  const myKelas = teacher?.kelasWali ?? "";

  const myStudents = DUMMY_STUDENTS.filter((s) => s.kelas === myKelas);
  const myStudentIds = myStudents.map((s) => s.id);

  const myNotifs = notifications.filter((n) => myStudentIds.includes(n.studentId));

  return (
    <div className="animate-fadeIn">
      <h1 style={{ fontSize: 24, fontWeight: 800, marginBottom: 8 }}>Notifikasi Wali Murid</h1>
      <p style={{ color: "var(--text-muted)", fontSize: 14, marginBottom: 24 }}>Log pengiriman untuk Kelas {myKelas}</p>

      <div className="glass-card" style={{ padding: 24 }}>
        <div style={{ fontSize: 15, fontWeight: 700, marginBottom: 16, display: "flex", alignItems: "center", gap: 8 }}>
          <Bell size={18} color="var(--accent-primary)" /> Log Pengiriman ({myNotifs.length})
        </div>

        {myNotifs.length === 0 ? (
          <div style={{ textAlign: "center", color: "var(--text-muted)", padding: "40px 0" }}>Belum ada log notifikasi.</div>
        ) : (
          <div style={{ overflowX: "auto" }}>
            <table className="data-table">
              <thead>
                <tr><th>Waktu</th><th>Siswa</th><th>Pesan</th><th>Tipe</th><th>Status</th></tr>
              </thead>
              <tbody>
                {myNotifs.map((n) => {
                  const student = myStudents.find((s) => s.id === n.studentId);
                  return (
                    <tr key={n.id}>
                      <td style={{ whiteSpace: "nowrap", fontSize: 12 }}>{new Date(n.sentAt).toLocaleString("id-ID")}</td>
                      <td style={{ fontWeight: 500 }}>{student?.name}</td>
                      <td style={{ fontSize: 12, maxWidth: 260 }}>{n.message}</td>
                      <td>
                        <span style={{ fontSize: 11, fontWeight: 600, textTransform: "capitalize", padding: "2px 8px", borderRadius: 10,
                          background: n.type === "push" ? "rgba(99,102,241,0.15)" : n.type === "whatsapp" ? "rgba(16,185,129,0.15)" : "rgba(59,130,246,0.15)",
                          color: n.type === "push" ? "#6366f1" : n.type === "whatsapp" ? "#10b981" : "#3b82f6" }}>
                          {n.type}
                        </span>
                      </td>
                      <td>
                        <span style={{ color: n.status === "sent" ? "#10b981" : "#ef4444", fontSize: 12, fontWeight: 600 }}>
                          {n.status === "sent" ? "✓ Terkirim" : "✗ Gagal"}
                        </span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";
import { useStore } from "@/lib/store";
import { useEffect, useState } from "react";
import { Users, ClipboardList, CheckCircle, Clock, UserX, BarChart3 } from "lucide-react";
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from "recharts";
import StatusBadge from "@/components/StatusBadge";
import { format } from "date-fns";
import { id as idLocale } from "date-fns/locale";

export default function GuruDashboard() {
  const { currentUser, students, records, getDashboardStats } = useStore();
  const [mounted, setMounted] = useState(false);

  // eslint-disable-next-line react-hooks/set-state-in-effect
  // eslint-disable-next-line react-hooks/set-state-in-effect
  useEffect(() => setMounted(true), []);

  if (!currentUser || !mounted) return null;

  const teacher = currentUser as import("@/lib/types").Teacher;
  const myKelas = teacher.kelasWali ?? "";
  const myStudents = students.filter((s) => s.kelas === myKelas);

  const today = new Date().toISOString().split("T")[0];
  const todayRecords = records.filter((r) => r.date === today && r.kelas === myKelas);

  const hadir  = todayRecords.filter((r) => r.status === "hadir").length;
  const telat  = todayRecords.filter((r) => r.status === "terlambat").length;
  const absen  = myStudents.length - todayRecords.filter((r) => r.status !== "tidak_hadir").length;

  const stats = getDashboardStats();
  const weeklyForClass = stats.weeklyData; // simplified

  return (
    <div className="animate-fadeIn">
      <div style={{ marginBottom: 28 }}>
        <h1 style={{ fontSize: 26, fontWeight: 800 }}>Dashboard Guru</h1>
        <p style={{ color: "var(--text-muted)", fontSize: 14 }}>
          {format(new Date(), "EEEE, dd MMMM yyyy", { locale: idLocale })} · Kelas Wali: <strong style={{ color: "var(--text-primary)" }}>{myKelas || "–"}</strong>
        </p>
      </div>

      {/* Stats */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(180px,1fr))", gap: 16, marginBottom: 24 }}>
        {[
          { label: "Total Siswa",    value: myStudents.length, icon: Users,         type: "primary", color: "#6366f1" },
          { label: "Hadir Hari Ini", value: hadir,             icon: CheckCircle,   type: "success", color: "#10b981" },
          { label: "Terlambat",      value: telat,             icon: Clock,         type: "warning", color: "#f59e0b" },
          { label: "Tidak Hadir",    value: absen,             icon: UserX,         type: "danger",  color: "#ef4444" },
        ].map((c) => (
          <div key={c.label} className={`stat-card ${c.type}`}>
            <c.icon size={20} color={c.color} style={{ marginBottom: 10 }} />
            <div style={{ fontSize: 32, fontWeight: 800 }}>{c.value}</div>
            <div style={{ fontSize: 12, color: "var(--text-muted)", marginTop: 4 }}>{c.label}</div>
          </div>
        ))}
      </div>

      {/* Chart */}
      <div className="glass-card" style={{ padding: 24, marginBottom: 24 }}>
        <div style={{ fontSize: 15, fontWeight: 700, marginBottom: 16, display: "flex", alignItems: "center", gap: 8 }}>
          <BarChart3 size={18} color="var(--accent-primary)" /> Kehadiran Kelas 7 Hari Terakhir
        </div>
        <ResponsiveContainer width="100%" height={200}>
          <BarChart data={weeklyForClass} barGap={4}>
            <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" />
            <XAxis dataKey="day" tick={{ fill: "var(--text-muted)", fontSize: 12 }} axisLine={false} tickLine={false} />
            <YAxis tick={{ fill: "var(--text-muted)", fontSize: 12 }} axisLine={false} tickLine={false} />
            <Tooltip contentStyle={{ background: "#0f1629", border: "1px solid var(--border-glass)", borderRadius: 10 }} />
            <Bar dataKey="hadir"       name="Hadir"       fill="#10b981" radius={[4,4,0,0]} />
            <Bar dataKey="terlambat"   name="Terlambat"   fill="#f59e0b" radius={[4,4,0,0]} />
            <Bar dataKey="tidak_hadir" name="Tidak Hadir" fill="#ef4444" radius={[4,4,0,0]} />
          </BarChart>
        </ResponsiveContainer>
      </div>

      {/* Today's class attendance */}
      <div className="glass-card" style={{ padding: 24 }}>
        <div style={{ fontSize: 15, fontWeight: 700, marginBottom: 16, display: "flex", alignItems: "center", gap: 8 }}>
          <ClipboardList size={18} color="var(--accent-primary)" /> Absensi Kelas Hari Ini
        </div>
        <div style={{ overflowX: "auto" }}>
          <table className="data-table">
            <thead>
              <tr><th>No</th><th>Nama Siswa</th><th>Status</th><th>Jam Masuk</th><th>Verifikasi</th></tr>
            </thead>
            <tbody>
              {myStudents.map((s, i) => {
                const rec = todayRecords.find((r) => r.studentId === s.id);
                return (
                  <tr key={s.id}>
                    <td style={{ color: "var(--text-muted)" }}>{i + 1}</td>
                    <td style={{ fontWeight: 500, color: "var(--text-primary)" }}>{s.name}</td>
                    <td><StatusBadge status={rec?.status ?? "tidak_hadir"} /></td>
                    <td>{rec?.checkIn?.time ?? "–"}</td>
                    <td style={{ fontSize: 12 }}>
                      {rec?.checkIn ? <span style={{ color: "#10b981" }}>✓ Wajah & GPS</span>
                        : <span style={{ color: "var(--text-muted)" }}>–</span>}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

"use client";
import { useStore } from "@/lib/store";
import { useState, useEffect } from "react";
import { Megaphone, Bell, AlertTriangle, Info, Calendar } from "lucide-react";
import { AnnouncementPriority } from "@/lib/types";
import { format } from "date-fns";
import { id as idLocale } from "date-fns/locale";

const PRIORITY_CONFIG: Record<AnnouncementPriority, { label: string; color: string; bg: string; icon: React.ElementType }> = {
  normal:  { label: "Normal",  color: "#3b82f6", bg: "rgba(59,130,246,0.08)",  icon: Info },
  penting: { label: "Penting", color: "#f59e0b", bg: "rgba(245,158,11,0.08)",  icon: Bell },
  darurat: { label: "Darurat", color: "#ef4444", bg: "rgba(239,68,68,0.08)",   icon: AlertTriangle },
};

export default function GuruPengumumanPage() {
  const { currentUser, getAnnouncementsForUser } = useStore();
  const [mounted, setMounted] = useState(false);

  // eslint-disable-next-line react-hooks/set-state-in-effect
  // eslint-disable-next-line react-hooks/set-state-in-effect
  useEffect(() => setMounted(true), []);
  if (!currentUser || !mounted) return null;

  const teacher = currentUser as import("@/lib/types").Teacher;
  const announcements = getAnnouncementsForUser(currentUser.role, teacher.kelasWali)
    .sort((a, b) => new Date(b.publishedAt).getTime() - new Date(a.publishedAt).getTime());

  return (
    <div className="animate-fadeIn">
      <div style={{ marginBottom: 28 }}>
        <h1 style={{ fontSize: 26, fontWeight: 800, marginBottom: 4, display: "flex", alignItems: "center", gap: 10 }}>
          <Megaphone size={24} color="var(--accent-primary)" /> Pengumuman
        </h1>
        <p style={{ color: "var(--text-muted)", fontSize: 14 }}>Pengumuman resmi dari sekolah untuk Anda.</p>
      </div>

      {announcements.length === 0 ? (
        <div className="glass-card" style={{ padding: 64, textAlign: "center", color: "var(--text-muted)" }}>
          <Megaphone size={56} style={{ margin: "0 auto 16px", opacity: 0.3 }} />
          <div style={{ fontSize: 16, fontWeight: 600, marginBottom: 8 }}>Tidak ada pengumuman</div>
          <div style={{ fontSize: 14 }}>Pengumuman terbaru dari sekolah akan tampil di sini.</div>
        </div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          {announcements.map(ann => {
            const cfg = PRIORITY_CONFIG[ann.priority];
            const Icon = cfg.icon;
            return (
              <div key={ann.id} className="glass-card" style={{ padding: 24, borderLeft: `4px solid ${cfg.color}` }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10, flexWrap: "wrap" }}>
                  <span style={{ display: "flex", alignItems: "center", gap: 5, fontSize: 12, fontWeight: 600,
                    padding: "3px 10px", borderRadius: 12, background: cfg.bg, color: cfg.color }}>
                    <Icon size={12} /> {cfg.label}
                  </span>
                  <div style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 12, color: "var(--text-muted)" }}>
                    <Calendar size={12} />
                    {format(new Date(ann.publishedAt), "EEEE, dd MMMM yyyy HH:mm", { locale: idLocale })}
                  </div>
                </div>
                <h2 style={{ fontSize: 17, fontWeight: 700, marginBottom: 10 }}>{ann.title}</h2>
                <p style={{ fontSize: 14, color: "var(--text-secondary)", lineHeight: 1.7 }}>{ann.content}</p>
                <div style={{ marginTop: 14, fontSize: 12, color: "var(--text-muted)" }}>
                  Dari: {ann.authorName}
                  {ann.expiresAt && ` · Berlaku hingga: ${format(new Date(ann.expiresAt), "dd MMM yyyy", { locale: idLocale })}`}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

"use client";
import { useStore } from "@/lib/store";
import { useState } from "react";
import { User, Mail, Phone, Save, Lock, Eye, EyeOff, Shield } from "lucide-react";
import Toast, { ToastType } from "@/components/Toast";

const ROLE_LABEL: Record<string, string> = {
  admin: "Administrator", guru: "Guru / Tenaga Pengajar", siswa: "Siswa", wali: "Wali Murid",
};

export default function ProfilPage() {
  const { currentUser, updateProfile } = useStore();
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);
  const [showPasswordSection, setShowPasswordSection] = useState(false);
  const [showCurrentPwd, setShowCurrentPwd] = useState(false);
  const [showNewPwd, setShowNewPwd] = useState(false);

  const [form, setForm] = useState({
    name: currentUser?.name ?? "",
    phone: currentUser?.phone ?? "",
  });
  const [pwd, setPwd] = useState({ current: "", newPwd: "", confirm: "" });

  if (!currentUser) return null;

  const handleSaveProfile = () => {
    if (!form.name.trim()) {
      setToast({ message: "Nama tidak boleh kosong", type: "error" });
      return;
    }
    updateProfile({ name: form.name, phone: form.phone });
    setToast({ message: "Profil berhasil diperbarui!", type: "success" });
  };

  const handleChangePassword = () => {
    if (pwd.current !== "password123") {
      setToast({ message: "Password saat ini tidak sesuai", type: "error" });
      return;
    }
    if (pwd.newPwd.length < 8) {
      setToast({ message: "Password baru minimal 8 karakter", type: "error" });
      return;
    }
    if (pwd.newPwd !== pwd.confirm) {
      setToast({ message: "Konfirmasi password tidak sesuai", type: "error" });
      return;
    }
    setPwd({ current: "", newPwd: "", confirm: "" });
    setShowPasswordSection(false);
    setToast({ message: "Password berhasil diubah!", type: "success" });
  };

  const roleInfo = (() => {
    const r = currentUser.role;
    if (r === "guru") {
      const g = currentUser as import("@/lib/types").Teacher;
      return [
        { label: "NIP", value: g.nip },
        { label: "Kelas Wali", value: g.kelasWali || "–" },
        { label: "Mata Pelajaran", value: g.mataPelajaran?.join(", ") || "–" },
      ];
    }
    if (r === "siswa") {
      const s = currentUser as import("@/lib/types").Student;
      return [
        { label: "NISN", value: s.nisn },
        { label: "Kelas", value: s.kelas },
        { label: "Jurusan", value: s.jurusan },
      ];
    }
    if (r === "wali") {
      const w = currentUser as import("@/lib/types").Parent;
      return [{ label: "No. WhatsApp", value: w.waNumber || "–" }];
    }
    return [];
  })();

  return (
    <div className="animate-fadeIn" style={{ maxWidth: 680 }}>
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <div style={{ marginBottom: 28 }}>
        <h1 style={{ fontSize: 26, fontWeight: 800, marginBottom: 4 }}>Profil Saya</h1>
        <p style={{ color: "var(--text-muted)", fontSize: 14 }}>Kelola informasi akun dan keamanan Anda.</p>
