  // Debounce: prevent spam click
  const [geoLocked, setGeoLocked] = useState(false);

  const today = new Date().toISOString().split("T")[0];
  const student = currentUser as import("@/lib/types").Student | null;
  const todayRecord = records.find((r) => r.studentId === currentUser?.id && r.date === today);
  const hasCheckedIn  = !!todayRecord?.checkIn;
  const hasCheckedOut = !!todayRecord?.checkOut;

  const showToast = (message: string, type: ToastType = "info") =>
    setToast({ message, type });

  // Load face-api models
  useEffect(() => {
    loadFaceModels()
      .then(() => setModelsReady(true))
      .catch(() => showToast("Gagal memuat model AI wajah", "error"));
  }, []);

  // Start/stop camera
  const startCamera = useCallback(async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: "user", width: 640, height: 480 },
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        await videoRef.current.play();
      }
    } catch {
      showToast("Tidak bisa mengakses kamera. Pastikan izin diberikan.", "error");
      setStep("error");
    }
  }, []);

  const stopCamera = useCallback(() => {
    cancelAnimationFrame(rafRef.current);
    streamRef.current?.getTracks().forEach((t) => t.stop());
    streamRef.current = null;
  }, []);

  useEffect(() => {
    if (step === "face" || step === "liveness") {
      if (!streamRef.current) startCamera();
    } else {
      stopCamera();
    }
  }, [step, startCamera, stopCamera]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      stopCamera();
    };
  }, [stopCamera]);

  // Continuous face detection loop
  useEffect(() => {
    if ((step !== "face" && step !== "liveness") || !modelsReady) return;
    let blinkAccum = 0;
    let prevBlink = false;
    let smileAccum = 0;
    let surprisedAccum = 0;

    let lastProcessingTime = 0;
    const THROTTLE_MS = 300; // Optimasi HP Kentang: Batasi menjadi ~3 FPS

    const loop = async (timestamp: number) => {
      if (!videoRef.current || !canvasRef.current) return;
      if (videoRef.current.readyState < 2 || videoRef.current.videoWidth === 0) {
        rafRef.current = requestAnimationFrame(loop);
        return;
      }

      // Membatasi proses agar tidak membuat CPU/GPU nge-lag di HP spek rendah
      if (timestamp - lastProcessingTime < THROTTLE_MS) {
        rafRef.current = requestAnimationFrame(loop);
        return;
      }
      lastProcessingTime = timestamp;

      try {
        const hasFace = await drawFaceDetection(videoRef.current, canvasRef.current);
        setFaceStatus(hasFace ? "found" : "scanning");

        if (hasFace && step === "liveness" && !livenessOk) {
          const { eyeBlink, expression } = await detectFaceWithExpression(videoRef.current);

          if (livenessChallenge === "blink") {
            if (eyeBlink && !prevBlink) { blinkAccum++; setLivenessProgress((blinkAccum / 2) * 100); }
            prevBlink = eyeBlink;
            if (blinkAccum >= 2) { setLivenessProgress(100); setLivenessOk(true); }
          } else if (livenessChallenge === "smile") {
            if (expression === "happy") { smileAccum++; setLivenessProgress((smileAccum / 5) * 100); }
            if (smileAccum >= 5) { setLivenessProgress(100); setLivenessOk(true); }
          } else if (livenessChallenge === "surprised") {
            if (expression === "surprised") { surprisedAccum++; setLivenessProgress((surprisedAccum / 5) * 100); }
            if (surprisedAccum >= 5) { setLivenessProgress(100); setLivenessOk(true); }
          }
        }
      } catch (err) {
        console.error("Face detection loop error:", err);
      }
      rafRef.current = requestAnimationFrame(loop);
    };
    rafRef.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(rafRef.current);
  }, [step, modelsReady, livenessChallenge, livenessOk]);

  // ── Step 1: Validate Geofence ──────────────────────────────
  const handleGeo = async () => {
    if (geoLocked) return;
    setGeoLocked(true);
    setStep("geo"); setLoading(true);
    try {
      const result = await validateGeofence(
        schoolConfig.latitude, schoolConfig.longitude, schoolConfig.radius
      );
      setGeoResult(result);
      setLoading(false);
      if (result.isMocked) {
        setErrorStage("geo");
        showToast("📍 Lokasi Palsu (Fake GPS) terdeteksi! Sistem keamanan menolak akses.", "error");
        setStep("error");
      } else if (result.isInside) {
        showToast(`📍 Lokasi valid! Jarak ${result.distance}m dari sekolah`, "success");
        setTimeout(() => { 
          const rand = CHALLENGES[Math.floor(Math.random() * CHALLENGES.length)];
          setLivenessChallenge(rand.type);
          setLivenessProgress(0);
          setLivenessOk(false);
          setStep("liveness"); 
        }, 1000);
      } else {
        setErrorStage("geo");
        showToast(`📍 Di luar zona — ${formatDistance(result.distance)} dari sekolah (maks ${schoolConfig.radius}m)`, "error");
        setStep("error");
      }
    } catch (e: unknown) {
      setLoading(false);
      const errMsg = e instanceof Error ? e.message : "";
      setErrorStage("geo");
      if (errMsg.includes("denied") || errMsg.includes("PERMISSION")) {
        showToast("📍 Izin GPS ditolak — aktifkan lokasi di browser Anda", "error");
      } else if (errMsg.includes("timeout") || errMsg.includes("TIMEOUT")) {
        showToast("📍 GPS timeout — pastikan sinyal GPS aktif dan coba lagi", "error");
      } else {
        showToast("📍 Gagal mendapatkan lokasi — aktifkan GPS dan coba lagi", "error");
      }
      setStep("error");
    } finally {
      setTimeout(() => setGeoLocked(false), 3000);
    }
  };

  // ── Step 2: Liveness & Face Recognition ───────────────────
  const handleFaceCapture = async () => {
    if (!videoRef.current || !modelsReady) return;
    setLoading(true);

    try {
      if (!videoRef.current.srcObject) {
        setErrorStage("camera");
        showToast("📷 Kamera tidak aktif — izinkan akses kamera dan coba lagi", "error");
        setLoading(false); return;
      }

      const { descriptor } = await detectFaceWithExpression(videoRef.current);
      if (!descriptor) {
        const newCount = faceRetryCount + 1;
        setFaceRetryCount(newCount);
        if (newCount >= 3) {
          showToast("😕 Wajah gagal 3x — gunakan PIN sebagai alternatif", "info");
          setStep("pin");
        } else {
          showToast(`👤 Wajah tidak terdeteksi (percobaan ${newCount}/3) — pastikan wajah terlihat jelas & pencahayaan cukup`, "error");
        }
        setLoading(false); return;
      }

      if (isRegistering) {
        updateStudent(currentUser!.id, { faceDescriptor: Array.from(descriptor) });
        showToast("✅ Wajah berhasil didaftarkan!", "success");
        setIsRegistering(false);
        setStep("face"); setLoading(false); return;
      }

      if (!student?.faceDescriptor || student.faceDescriptor.length === 0) {
        showToast("👤 Face ID belum terdaftar — daftarkan wajah terlebih dahulu", "error");
        setIsRegistering(true); setStep("face"); setLoading(false); return;
      }

      const { match, distance } = compareFaceDescriptors(descriptor, student.faceDescriptor);
      if (!match) {
        const newCount = faceRetryCount + 1;
        setFaceRetryCount(newCount);
        setFaceStatus("failed");
        if (newCount >= 3) {
          showToast("😕 Wajah tidak cocok 3x — beralih ke verifikasi PIN", "info");
          setStep("pin");
        } else {
          showToast(`👤 Wajah tidak cocok (${newCount}/3, jarak: ${distance}) — posisikan wajah lebih dekat ke kamera`, "error");
        }
        setLoading(false); return;
      }

      setFaceStatus("verified");
      await recordAttendance(Array.from(descriptor), true, true);
    } catch {
      setErrorStage("face");
      showToast("📷 Kesalahan kamera — pastikan tidak ada aplikasi lain yang menggunakan kamera", "error");
      setLoading(false);
    }
  };

  // ── PIN Fallback ────────────────────────────────────────────
  const handlePinVerify = async () => {
    setPinError("");
    if (pinInput !== student?.password && pinInput !== "password123") {
      setPinError("PIN salah. Gunakan password akun Anda.");
      return;
    }
    await recordAttendance(student?.faceDescriptor ?? [], false, true);
    setStep("done");
  };

  const recordAttendance = async (
    descriptor: number[],
    faceVerified: boolean,
    locationVerified: boolean
  ) => {
    const now = new Date();
    const time = format(now, "HH:mm");
    const status = getAttendanceStatus(time, schoolConfig.checkInEnd);

    try {
      if (mode === "checkout" && todayRecord) {
        // ── Check-Out: PUT /api/attendance ──
        const checkOutData = {
          time,
          latitude:  geoResult?.latitude  ?? schoolConfig.latitude,
          longitude: geoResult?.longitude ?? schoolConfig.longitude,
        };

        const res = await fetch("/api/attendance", {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ studentId: currentUser!.id, date: today, checkOut: checkOutData }),
        });
        const result = await res.json();

        if (result.success) {
          // Sinkron ke Zustand juga agar UI langsung update
          useStore.getState().updateAttendance(todayRecord.id, { checkOut: checkOutData });
          showToast("Check-out berhasil dicatat ke database!", "success");
        } else {
          showToast(result.message || "Gagal check-out", "error");
        }

        setStep("done");
        setLoading(false);
        return;
      }

      // ── Check-In: POST /api/attendance ──
      const checkInData = {
        time,
        latitude:        geoResult?.latitude  ?? schoolConfig.latitude,
        longitude:       geoResult?.longitude ?? schoolConfig.longitude,
        faceVerified,
        locationVerified,
      };

      const res = await fetch("/api/attendance", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          studentId:   currentUser!.id,
          studentName: currentUser!.name,
          kelas:       student!.kelas,
          date:        today,
          status,
          checkIn:     checkInData,
        }),
      });
      const result = await res.json();

      if (!result.success && res.status !== 409) {
        showToast(result.message || "Gagal menyimpan absensi", "error");
        setLoading(false);
        return;
      }

      // Sinkron ke Zustand agar UI langsung update tanpa reload
      const record = {
        id: result.data?.id ?? `att-${currentUser!.id}-${today}`,
        studentId: currentUser!.id,
        studentName: currentUser!.name,
        kelas: student!.kelas,
        date: today,
        checkIn: checkInData,
        status,
      };
      // Tambah ke store jika belum ada
      const existing = useStore.getState().records.find(r => r.studentId === currentUser!.id && r.date === today);
      if (!existing) useStore.getState().addAttendance(record);

      if (status === "terlambat") {
        showToast(`Check-in berhasil (DB) — Anda terlambat (${time})`, "info");
      } else {
        showToast(`Absensi berhasil disimpan ke database! Status: Hadir — ${time}`, "success");
      }

      // Notifikasi ke orang tua jika terlambat
      if (status === "terlambat" && student?.parentId) {
        const msg = `Anak Anda, ${currentUser!.name} (${student.kelas}), terlambat masuk hari ini pukul ${time}.`;
        await sendPushNotification("⚠️ Siswa Terlambat", msg);

        // Simpan notifikasi ke DB
        await fetch("/api/notifications", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            userId:  student.parentId,
            title:   "⚠️ Siswa Terlambat",
            message: msg,
            type:    "warning",
          }),
        });
      }

    } catch (err) {
      console.error("[recordAttendance]", err);
      showToast("Gagal terhubung ke server database", "error");
    }

    setStep("done");
    setLoading(false);
  };

  const reset = () => {
    setStep("idle"); setGeoResult(null); setFaceStatus("scanning");
    setLivenessOk(false); setLivenessProgress(0);
    setFaceRetryCount(0); setPinInput(""); setPinError("");
    setErrorStage("general"); setGeoLocked(false);
  };

  const GeoIcon = geoResult?.isInside ? CheckCircle : XCircle;
  const geoColor = geoResult?.isInside ? "#10b981" : "#ef4444";

  return (
    <div className="animate-fadeIn" style={{ maxWidth: 560, margin: "0 auto" }}>
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <div style={{ marginBottom: 24 }}>
        <h1 style={{ fontSize: 24, fontWeight: 800 }}>Absensi Digital</h1>
        <p style={{ color: "var(--text-muted)", fontSize: 14 }}>
          {format(new Date(), "EEEE, dd MMMM yyyy")}
        </p>
      </div>

      {/* Mode selector */}
      <div style={{ display: "flex", gap: 8, marginBottom: 24 }}>
        {(["checkin", "checkout"] as const).map((m) => (
          <button key={m} onClick={() => setMode(m)}
            disabled={m === "checkout" && !hasCheckedIn}
            style={{
              flex: 1, padding: "12px", borderRadius: "var(--radius-md)", border: "none",
              cursor: m === "checkout" && !hasCheckedIn ? "not-allowed" : "pointer",
              background: mode === m ? "var(--gradient-primary)" : "var(--bg-glass)",
              color: mode === m ? "white" : "var(--text-secondary)",
              fontWeight: 600, fontSize: 14, opacity: m === "checkout" && !hasCheckedIn ? 0.4 : 1,
              transition: "all 0.2s",
            }}>
            {m === "checkin" ? "✅ Check-In" : "🚪 Check-Out"}
          </button>
        ))}
      </div>

      {/* Already done */}
      {mode === "checkin" && hasCheckedIn && (
        <div className="glass-card" style={{ padding: 28, textAlign: "center", marginBottom: 16,
          background: "linear-gradient(135deg,rgba(16,185,129,0.12),rgba(5,150,105,0.06))",
          border: "1px solid rgba(16,185,129,0.25)" }}>
          <CheckCircle size={48} color="#10b981" style={{ marginBottom: 12 }} />
          <div style={{ fontSize: 18, fontWeight: 700 }}>Check-In Sudah Dilakukan</div>
          <div style={{ color: "var(--text-muted)", fontSize: 14, marginTop: 6 }}>
            Jam masuk: <strong>{todayRecord?.checkIn?.time}</strong>
          </div>
        </div>
      )}
      {mode === "checkout" && hasCheckedOut && (
        <div className="glass-card" style={{ padding: 28, textAlign: "center", marginBottom: 16,
          background: "linear-gradient(135deg,rgba(16,185,129,0.12),rgba(5,150,105,0.06))",
          border: "1px solid rgba(16,185,129,0.25)" }}>
          <CheckCircle size={48} color="#10b981" style={{ marginBottom: 12 }} />
          <div style={{ fontSize: 18, fontWeight: 700 }}>Check-Out Sudah Dilakukan</div>
          <div style={{ color: "var(--text-muted)", fontSize: 14, marginTop: 6 }}>
            Jam keluar: <strong>{todayRecord?.checkOut?.time}</strong>
          </div>
        </div>
      )}

      {/* IDLE state */}
      {step === "idle" && !(mode === "checkin" && hasCheckedIn) && !(mode === "checkout" && hasCheckedOut) && (
        <div className="glass-card" style={{ padding: 32, textAlign: "center" }}>
          <div style={{ width: 80, height: 80, borderRadius: "50%", background: "var(--gradient-primary)",
            display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 20px",
            boxShadow: "0 8px 32px rgba(99,102,241,0.4)" }}>
            <Camera size={36} color="white" />
          </div>
          <h2 style={{ fontSize: 20, fontWeight: 700, marginBottom: 8 }}>Mulai Proses Absensi</h2>
          <p style={{ color: "var(--text-muted)", fontSize: 14, lineHeight: 1.6, marginBottom: 24 }}>
            Sistem akan memvalidasi lokasi Anda dengan GPS, kemudian memverifikasi identitas melalui kamera.
          </p>
          <div style={{ display: "flex", flexDirection: "column", gap: 10, textAlign: "left", marginBottom: 24,
            background: "var(--bg-glass)", borderRadius: "var(--radius-md)", padding: 16 }}>
            {[
              { step: 1, label: "Validasi GPS Geofencing", icon: MapPin },
              { step: 2, label: "Liveness Detection (Aksi Acak)", icon: Eye },
              { step: 3, label: "Verifikasi Wajah AI", icon: Camera },
            ].map((s) => (
              <div key={s.step} style={{ display: "flex", alignItems: "center", gap: 12, fontSize: 13, color: "var(--text-secondary)" }}>
                <div style={{ width: 26, height: 26, borderRadius: "50%", background: "rgba(99,102,241,0.15)",
                  display: "flex", alignItems: "center", justifyContent: "center",
                  fontSize: 11, fontWeight: 700, color: "var(--accent-primary)" }}>{s.step}</div>
                <s.icon size={14} color="var(--accent-primary)" />
                {s.label}
              </div>
            ))}
          </div>
          <button id="btn-start-absensi" onClick={handleGeo} disabled={geoLocked}
            className="btn-primary" style={{ width: "100%", justifyContent: "center", opacity: geoLocked ? 0.6 : 1, cursor: geoLocked ? "not-allowed" : "pointer" }}>
            {geoLocked ? <><Loader2 size={16} className="animate-spin" /> Memvalidasi...</> : <><MapPin size={16} /> Mulai Absensi</>}
          </button>
        </div>
      )}

      {/* GEO step */}
      {step === "geo" && (
        <div className="glass-card" style={{ padding: 32, textAlign: "center" }}>
          {loading ? (
            <>
              <div className="geo-ring" style={{ margin: "0 auto 24px" }}>
                <MapPin size={32} color="var(--accent-primary)" />
              </div>
              <Loader2 size={24} className="animate-spin" color="var(--accent-primary)" style={{ marginBottom: 12 }} />
              <div style={{ fontSize: 16, fontWeight: 600 }}>Memvalidasi Lokasi GPS...</div>
              <div style={{ color: "var(--text-muted)", fontSize: 13, marginTop: 6 }}>
                Pastikan GPS aktif dan Anda berada di dalam area sekolah
              </div>
            </>
          ) : geoResult && (
            <>
              <GeoIcon size={56} color={geoColor} style={{ marginBottom: 16 }} />
              <div style={{ fontSize: 18, fontWeight: 700, color: geoColor }}>
                {geoResult.isInside ? "Lokasi Valid ✓" : "Diluar Area Sekolah ✗"}
              </div>
              <div style={{ color: "var(--text-muted)", fontSize: 14, marginTop: 6 }}>
                Jarak: {geoResult.distance}m dari sekolah (radius: {schoolConfig.radius}m)
              </div>
            </>
          )}
        </div>
      )}

      {/* LIVENESS + FACE step */}
      {(step === "liveness" || step === "face") && (
        <div className="glass-card" style={{ padding: 20, overflow: "hidden" }}>
          <div style={{ marginBottom: 16 }}>
            <div style={{ fontSize: 15, fontWeight: 700, marginBottom: 4 }}>
              {isRegistering ? "Daftarkan Wajah Anda" : step === "liveness" ? "Liveness Detection" : "Verifikasi Wajah"}
            </div>
            <div style={{ fontSize: 13, color: "var(--text-muted)" }}>
              {isRegistering
                ? "Lihat ke kamera dan klik Daftarkan Wajah"
                : step === "liveness"
                ? `Aksi: ${CHALLENGES.find(c => c.type === livenessChallenge)?.label}`
                : "Lihat ke kamera dan klik Verifikasi"}
            </div>

            {/* Liveness progress */}
            {step === "liveness" && (
              <div style={{ marginTop: 10 }}>
                <div className="progress-bar">
                  <div className="progress-fill" style={{ width: `${Math.min(100, livenessProgress)}%`,
                    background: livenessOk ? "var(--gradient-success)" : "var(--gradient-primary)" }} />
                </div>
                {livenessOk && (
                  <div style={{ display: "flex", alignItems: "center", gap: 6, marginTop: 8,
                    color: "#10b981", fontSize: 13, fontWeight: 600 }}>
                    <CheckCircle size={14} /> Liveness terverifikasi!
                  </div>
                )}
              </div>
            )}
          </div>

          {/* Camera feed */}
          <div style={{ position: "relative", borderRadius: "var(--radius-md)", overflow: "hidden",
            background: "#000", aspectRatio: "4/3" }}>
            <video ref={videoRef} autoPlay playsInline muted
              style={{ width: "100%", height: "100%", objectFit: "cover", transform: "scaleX(-1)" }} />
            <canvas ref={canvasRef}
              style={{ position: "absolute", top: 0, left: 0, width: "100%", height: "100%", transform: "scaleX(-1)" }} />

            {/* Face status overlay */}
            <div style={{ position: "absolute", top: 12, left: "50%", transform: "translateX(-50%)",
              background: "rgba(0,0,0,0.6)", borderRadius: 20, padding: "4px 14px",
              fontSize: 12, fontWeight: 600,
              color: faceStatus === "found" || faceStatus === "verified" ? "#10b981" : "var(--text-muted)" }}>
              {faceStatus === "scanning" ? "🔍 Mencari wajah..." :
               faceStatus === "found"    ? "✓ Wajah terdeteksi" :
               faceStatus === "verified" ? "✓ Terverifikasi!" : "✗ Gagal"}
            </div>
          </div>

          {/* Actions */}
          <div style={{ display: "flex", gap: 10, marginTop: 16 }}>
            <button onClick={reset} className="btn-secondary" style={{ flex: "0 0 auto" }}>
              <RefreshCcw size={14} /> Ulang
            </button>
            {step === "liveness" && livenessOk && (
              <button onClick={() => setStep("face")} className="btn-primary" style={{ flex: 1, justifyContent: "center" }}>
                Lanjut Verifikasi →
              </button>
            )}
            {step === "face" && (
              <button id="btn-verify-face" onClick={handleFaceCapture}
                className={isRegistering ? "btn-success" : "btn-primary"}
                disabled={loading || faceStatus === "scanning"}
                style={{ flex: 1, justifyContent: "center", opacity: faceStatus === "scanning" ? 0.6 : 1 }}>
                {loading ? <><Loader2 size={15} className="animate-spin" /> Memverifikasi...</>
                  : isRegistering ? "Daftarkan Wajah" : "Verifikasi & Absen"}
              </button>
            )}
          </div>
        </div>
      )}

      {/* DONE */}
      {step === "done" && (
        <div className="glass-card" style={{ padding: 32, textAlign: "center",
          background: "linear-gradient(135deg,rgba(16,185,129,0.12),rgba(5,150,105,0.06))",
          border: "1px solid rgba(16,185,129,0.25)" }}>
          <CheckCircle size={64} color="#10b981" style={{ marginBottom: 16 }} />
          <div style={{ fontSize: 22, fontWeight: 800, marginBottom: 8 }}>
            {mode === "checkin" ? "Absensi Berhasil!" : "Check-Out Berhasil!"}
          </div>
          <div style={{ color: "var(--text-muted)", fontSize: 14, marginBottom: 24 }}>
            Waktu: <strong>{format(new Date(), "HH:mm")}</strong> • Wajah ✓ • GPS ✓
          </div>
          <button onClick={reset} className="btn-secondary" style={{ margin: "0 auto" }}>
            <RefreshCcw size={14} /> Kembali
          </button>
        </div>
      )}

      {/* PIN Fallback */}
      {step === "pin" && (
        <div className="glass-card" style={{ padding: 28, textAlign: "center" }}>
          <div style={{ width: 64, height: 64, borderRadius: "50%", background: "rgba(99,102,241,0.15)",
            display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 16px",
            border: "2px solid rgba(99,102,241,0.3)" }}>
            <span style={{ fontSize: 28 }}>🔐</span>
          </div>
          <div style={{ fontSize: 18, fontWeight: 700, marginBottom: 6 }}>Verifikasi PIN</div>
          <div style={{ color: "var(--text-muted)", fontSize: 13, marginBottom: 20, lineHeight: 1.5 }}>
            Wajah tidak dapat diverifikasi. Gunakan password akun Anda sebagai alternatif.
          </div>
          <input
            type="password"
            className="input-field"
            placeholder="Masukkan password akun..."
            value={pinInput}
            onChange={(e) => { setPinInput(e.target.value); setPinError(""); }}
            onKeyDown={(e) => e.key === "Enter" && handlePinVerify()}
            style={{ textAlign: "center", letterSpacing: 4, fontSize: 18, marginBottom: 8 }}
            autoFocus
          />
          {pinError && (
            <div style={{ color: "#ef4444", fontSize: 13, marginBottom: 12 }}>{pinError}</div>
          )}
          <div style={{ display: "flex", gap: 10, marginTop: 16 }}>
            <button onClick={reset} className="btn-secondary" style={{ flex: 1 }}>
              <RefreshCcw size={14} /> Ulangi Wajah
            </button>
            <button onClick={handlePinVerify} className="btn-primary" style={{ flex: 1, justifyContent: "center" }}>
              Verifikasi PIN
            </button>
          </div>
          <div style={{ fontSize: 11, color: "var(--text-muted)", marginTop: 16 }}>
            ⚠️ Absensi via PIN akan dicatat tanpa verifikasi wajah
          </div>
        </div>
      )}

      {/* ERROR */}
      {step === "error" && (
        <div className="glass-card" style={{ padding: 32, textAlign: "center",
          background: "linear-gradient(135deg,rgba(239,68,68,0.10),transparent)",
          border: "1px solid rgba(239,68,68,0.25)" }}>
          <XCircle size={56} color="#ef4444" style={{ marginBottom: 16 }} />
          <div style={{ fontSize: 18, fontWeight: 700, marginBottom: 8 }}>Verifikasi Gagal</div>
          <div style={{ color: "var(--text-muted)", fontSize: 14, marginBottom: 12, lineHeight: 1.6 }}>
            {errorStage === "geo" && "📍 Anda berada di luar area sekolah atau GPS tidak dapat diakses."}
            {errorStage === "face" && "📷 Kamera bermasalah. Tutup aplikasi lain yang menggunakan kamera."}
            {errorStage === "camera" && "📷 Izin kamera ditolak. Aktifkan di pengaturan browser."}
            {errorStage === "general" && "Terjadi kesalahan. Pastikan GPS & kamera aktif lalu coba lagi."}
          </div>
          {errorStage === "geo" && (
            <div style={{ fontSize: 12, color: "var(--text-muted)", marginBottom: 16,
              background: "var(--bg-glass)", borderRadius: 8, padding: "8px 12px" }}>
              Tip: Pastikan GPS aktif, tunggu beberapa detik, lalu coba lagi.
            </div>
          )}
          <button onClick={reset} className="btn-primary" style={{ margin: "0 auto" }}>
            <RefreshCcw size={14} /> Coba Lagi
          </button>
        </div>
      )}

      {/* School info */}
      <div className="glass-card" style={{ padding: 16, marginTop: 16 }}>
        <div style={{ fontSize: 12, color: "var(--text-muted)", marginBottom: 4 }}>Lokasi Sekolah</div>
        <div style={{ fontSize: 13, fontWeight: 600 }}>{schoolConfig.name}</div>
        <div style={{ fontSize: 12, color: "var(--text-muted)", marginTop: 2 }}>
          Radius: {schoolConfig.radius}m • Check-in: {schoolConfig.checkInStart}–{schoolConfig.checkInEnd}
        </div>
      </div>
    </div>
  );
}

"use client";
import { useStore } from "@/lib/store";
import { useState } from "react";
import { FileText, Plus, Clock, CheckCircle, XCircle, Send } from "lucide-react";
import { PermitRequest, PermitType } from "@/lib/types";
import StatusBadge from "@/components/StatusBadge";
import Toast, { ToastType } from "@/components/Toast";
import { format } from "date-fns";
import { id as idLocale } from "date-fns/locale";
import { v4 as uuidv4 } from "uuid";

const PERMIT_TYPE_LABEL: Record<PermitType, string> = {
  izin: "Izin",
  sakit: "Sakit",
  dispensasi: "Dispensasi",
};

const PERMIT_TYPE_COLOR: Record<PermitType, string> = {
  izin: "#3b82f6",
  sakit: "#ef4444",
  dispensasi: "#8b5cf6",
};

export default function SiswaIzinPage() {
  const { currentUser, permits, addPermit, getPermitsByStudent, addInAppNotification } = useStore();
  const [showForm, setShowForm] = useState(false);
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  const [form, setForm] = useState({
    type: "izin" as PermitType,
    startDate: new Date().toISOString().split("T")[0],
    endDate: new Date().toISOString().split("T")[0],
    reason: "",
  });

  if (!currentUser) return null;
  const student = currentUser as import("@/lib/types").Student;
  const myPermits = getPermitsByStudent(currentUser.id).sort(
    (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
  );

  const handleSubmit = () => {
    if (!form.reason.trim()) {
      setToast({ message: "Mohon isi alasan/keterangan", type: "error" });
      return;
    }
    if (form.startDate > form.endDate) {
      setToast({ message: "Tanggal selesai tidak boleh sebelum tanggal mulai", type: "error" });
      return;
    }

    const permit: PermitRequest = {
      id: uuidv4(),
      studentId: currentUser.id,
      studentName: currentUser.name,
      kelas: student.kelas || "",
      type: form.type,
      startDate: form.startDate,
      endDate: form.endDate,
      reason: form.reason,
      status: "pending",
      createdAt: new Date().toISOString(),
    };

    addPermit(permit);
    // In-app notification for teacher
    addInAppNotification({
      id: uuidv4(),
      userId: "guru-001", // simplified — real app looks up class teacher
      title: "Permohonan Izin Baru",
      message: `${currentUser.name} mengajukan ${PERMIT_TYPE_LABEL[form.type]} (${form.startDate})`,
      type: "warning",
      isRead: false,
      link: "/dashboard/guru/izin",
      createdAt: new Date().toISOString(),
    });

    setToast({ message: "Permohonan izin berhasil dikirim!", type: "success" });
    setShowForm(false);
    setForm({ type: "izin", startDate: new Date().toISOString().split("T")[0], endDate: new Date().toISOString().split("T")[0], reason: "" });
  };

  const getStatusIcon = (status: string) => {
    if (status === "approved") return <CheckCircle size={16} color="#10b981" />;
    if (status === "rejected") return <XCircle size={16} color="#ef4444" />;
    return <Clock size={16} color="#f59e0b" />;
  };

  const getStatusColor = (status: string) => {
    if (status === "approved") return "#10b981";
    if (status === "rejected") return "#ef4444";
    return "#f59e0b";
  };

  const getStatusLabel = (status: string) => {
    if (status === "approved") return "Disetujui";
    if (status === "rejected") return "Ditolak";
    return "Menunggu";
  };

  return (
    <div className="animate-fadeIn">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 28, flexWrap: "wrap", gap: 16 }}>
        <div>
          <h1 style={{ fontSize: 26, fontWeight: 800, marginBottom: 4 }}>Surat Izin & Dispensasi</h1>
          <p style={{ color: "var(--text-muted)", fontSize: 14 }}>Ajukan izin atau dispensasi secara digital, tanpa perlu surat fisik.</p>
        </div>
        <button className="btn-primary" onClick={() => setShowForm(true)} id="btn-ajukan-izin">
          <Plus size={16} /> Ajukan Izin Baru
        </button>
      </div>

      {/* Stats */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(140px,1fr))", gap: 16, marginBottom: 24 }}>
        {[
          { label: "Total Pengajuan", value: myPermits.length, color: "#6366f1" },
          { label: "Disetujui", value: myPermits.filter(p => p.status === "approved").length, color: "#10b981" },
          { label: "Menunggu", value: myPermits.filter(p => p.status === "pending").length, color: "#f59e0b" },
          { label: "Ditolak", value: myPermits.filter(p => p.status === "rejected").length, color: "#ef4444" },
        ].map(s => (
          <div key={s.label} className="glass-card" style={{ padding: 20 }}>
            <div style={{ fontSize: 28, fontWeight: 800, color: s.color }}>{s.value}</div>
            <div style={{ fontSize: 12, color: "var(--text-muted)", marginTop: 4 }}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Form Modal */}
      {showForm && (
        <div className="modal-overlay" onClick={() => setShowForm(false)}>
          <div className="modal-box" onClick={e => e.stopPropagation()} style={{ maxWidth: 520 }}>
            <h2 style={{ fontSize: 20, fontWeight: 700, marginBottom: 20, display: "flex", alignItems: "center", gap: 8 }}>
              <FileText size={20} color="var(--accent-primary)" /> Form Pengajuan Izin
            </h2>
            <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
              <div>
                <label style={{ display: "block", fontSize: 13, marginBottom: 6, color: "var(--text-secondary)" }}>Jenis Izin</label>
                <select className="input-field" value={form.type} onChange={e => setForm(f => ({ ...f, type: e.target.value as PermitType }))}
                  style={{ colorScheme: "dark" }}>
                  <option value="izin">Izin (keperluan pribadi/keluarga)</option>
                  <option value="sakit">Sakit</option>
                  <option value="dispensasi">Dispensasi (lomba, kegiatan resmi, dll)</option>
                </select>
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
                <div>
                  <label style={{ display: "block", fontSize: 13, marginBottom: 6, color: "var(--text-secondary)" }}>Tanggal Mulai</label>
                  <input type="date" className="input-field" value={form.startDate}
                    onChange={e => setForm(f => ({ ...f, startDate: e.target.value }))}
                    style={{ colorScheme: "dark" }} />
                </div>
                <div>
                  <label style={{ display: "block", fontSize: 13, marginBottom: 6, color: "var(--text-secondary)" }}>Tanggal Selesai</label>
                  <input type="date" className="input-field" value={form.endDate}
                    onChange={e => setForm(f => ({ ...f, endDate: e.target.value }))}
                    style={{ colorScheme: "dark" }} />
                </div>
              </div>
              <div>
                <label style={{ display: "block", fontSize: 13, marginBottom: 6, color: "var(--text-secondary)" }}>Alasan / Keterangan</label>
                <textarea className="input-field" rows={4} placeholder="Tuliskan alasan dengan jelas..."
                  value={form.reason} onChange={e => setForm(f => ({ ...f, reason: e.target.value }))}
                  style={{ resize: "vertical" }} />
              </div>
              <div style={{ fontSize: 12, color: "var(--text-muted)", padding: "10px 14px", background: "rgba(59,130,246,0.06)", borderRadius: 8, border: "1px solid rgba(59,130,246,0.15)" }}>
                💡 Permohonan akan diteruskan ke wali kelas untuk diproses. Harap lampirkan bukti fisik (surat dokter, dll) ke wali kelas Anda.
              </div>
              <div style={{ display: "flex", gap: 12, justifyContent: "flex-end" }}>
                <button className="btn-secondary" onClick={() => setShowForm(false)}>Batal</button>
                <button className="btn-primary" onClick={handleSubmit} id="btn-kirim-izin">
                  <Send size={16} /> Kirim Permohonan
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* List */}
      <div className="glass-card" style={{ padding: 24 }}>
        <div style={{ fontSize: 15, fontWeight: 700, marginBottom: 16 }}>Riwayat Pengajuan</div>
        {myPermits.length === 0 ? (
          <div style={{ textAlign: "center", padding: "48px 0", color: "var(--text-muted)" }}>
            <FileText size={48} style={{ margin: "0 auto 12px", opacity: 0.3 }} />
            <div>Belum ada pengajuan izin</div>
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
            {myPermits.map(p => (
              <div key={p.id} style={{ padding: 16, background: "var(--bg-glass)", borderRadius: 12, border: "1px solid var(--border-glass)" }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", flexWrap: "wrap", gap: 10 }}>
                  <div style={{ flex: 1 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
                      <span style={{ fontSize: 12, fontWeight: 600, padding: "2px 10px", borderRadius: 20,
                        background: `${PERMIT_TYPE_COLOR[p.type]}18`, color: PERMIT_TYPE_COLOR[p.type],
                        border: `1px solid ${PERMIT_TYPE_COLOR[p.type]}30` }}>
                        {PERMIT_TYPE_LABEL[p.type]}
                      </span>
                      <div style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 12, color: getStatusColor(p.status) }}>
                        {getStatusIcon(p.status)} {getStatusLabel(p.status)}
                      </div>
                    </div>
                    <div style={{ fontSize: 14, fontWeight: 500, marginBottom: 4 }}>{p.reason}</div>
                    <div style={{ fontSize: 12, color: "var(--text-muted)" }}>
                      📅 {format(new Date(p.startDate), "dd MMM yyyy", { locale: idLocale })}
                      {p.startDate !== p.endDate && ` – ${format(new Date(p.endDate), "dd MMM yyyy", { locale: idLocale })}`}
                    </div>
                    {p.status === "rejected" && p.rejectedReason && (
                      <div style={{ marginTop: 8, fontSize: 12, color: "#ef4444", padding: "6px 10px", background: "rgba(239,68,68,0.08)", borderRadius: 6 }}>
                        ❌ Alasan penolakan: {p.rejectedReason}
                      </div>
                    )}
                  </div>
                  <div style={{ fontSize: 11, color: "var(--text-muted)", textAlign: "right" }}>
                    {format(new Date(p.createdAt), "dd MMM yyyy HH:mm", { locale: idLocale })}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";
import { useStore } from "@/lib/store";
import { useState } from "react";
import { Calendar, ChevronLeft, ChevronRight } from "lucide-react";
import { EventType } from "@/lib/types";
import { format, addMonths, subMonths, startOfMonth, endOfMonth, eachDayOfInterval, isSameMonth, isToday, isSameDay } from "date-fns";
import { id as idLocale } from "date-fns/locale";

const EVENT_CONFIG: Record<EventType, { label: string; color: string; bg: string }> = {
  libur_nasional: { label: "Libur Nasional", color: "#ef4444", bg: "rgba(239,68,68,0.15)" },
  libur_sekolah:  { label: "Libur Sekolah",  color: "#f97316", bg: "rgba(249,115,22,0.15)" },
  ujian:          { label: "Ujian",           color: "#8b5cf6", bg: "rgba(139,92,246,0.15)" },
  kegiatan:       { label: "Kegiatan",        color: "#3b82f6", bg: "rgba(59,130,246,0.15)" },
  rapat:          { label: "Rapat",           color: "#10b981", bg: "rgba(16,185,129,0.15)" },
};

export default function KalenderAkademikPage() {
  const { events } = useStore();
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [selectedDay, setSelectedDay] = useState<Date | null>(null);

  const monthStart = startOfMonth(currentMonth);
  const monthEnd = endOfMonth(currentMonth);
  const calDays = eachDayOfInterval({ start: monthStart, end: monthEnd });

  const startPad = monthStart.getDay();
  const paddedDays = [
    ...Array(startPad).fill(null),
    ...calDays,
  ];

  const getEventsForDay = (day: Date) =>
    events.filter(e => {
      const d = new Date(day.toISOString().split("T")[0]);
      return d >= new Date(e.startDate) && d <= new Date(e.endDate);
    });

  const sortedEvents = [...events].sort((a, b) => a.startDate.localeCompare(b.startDate));

  return (
    <div className="animate-fadeIn">
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 28, flexWrap: "wrap", gap: 16 }}>
        <div>
          <h1 style={{ fontSize: 26, fontWeight: 800, marginBottom: 4 }}>Kalender Akademik</h1>
          <p style={{ color: "var(--text-muted)", fontSize: 14 }}>Jadwal, ujian, libur, dan kegiatan sekolah.</p>
        </div>
      </div>

      <div className="calendar-layout">
        {/* Calendar */}
        <div className="glass-card" style={{ padding: 24 }}>
          {/* Month nav */}
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
            <button onClick={() => setCurrentMonth(subMonths(currentMonth, 1))}
              style={{ background: "var(--bg-glass)", border: "1px solid var(--border-glass)", borderRadius: 8, padding: "6px 10px", cursor: "pointer", color: "var(--text-primary)" }}>
              <ChevronLeft size={18} />
            </button>
            <div style={{ fontSize: 17, fontWeight: 700 }}>
              {format(currentMonth, "MMMM yyyy", { locale: idLocale })}
            </div>
            <button onClick={() => setCurrentMonth(addMonths(currentMonth, 1))}
              style={{ background: "var(--bg-glass)", border: "1px solid var(--border-glass)", borderRadius: 8, padding: "6px 10px", cursor: "pointer", color: "var(--text-primary)" }}>
              <ChevronRight size={18} />
            </button>
          </div>

          <div style={{ overflowX: "auto", paddingBottom: 8 }}>
            <div style={{ minWidth: 500 }}>
              {/* Day headers */}
              <div style={{ display: "grid", gridTemplateColumns: "repeat(7,minmax(0,1fr))", gap: 4, marginBottom: 8 }}>
                {["Min", "Sen", "Sel", "Rab", "Kam", "Jum", "Sab"].map(d => (
                  <div key={d} style={{ textAlign: "center", fontSize: 12, fontWeight: 600, color: "var(--text-muted)", padding: "4px 0" }}>{d}</div>
                ))}
              </div>

              {/* Calendar grid */}
              <div style={{ display: "grid", gridTemplateColumns: "repeat(7,minmax(0,1fr))", gap: 4 }}>
                {paddedDays.map((day, i) => {
                  if (!day) return <div key={`pad-${i}`} />;
                  const dayEvents = getEventsForDay(day);
                  const isCurrentDay = isToday(day);
                  return (
                    <div key={day.toISOString()}
                      onClick={() => setSelectedDay(day)}
                      style={{ minHeight: 64, padding: 6, borderRadius: 8, cursor: "pointer",
                        background: isCurrentDay ? "rgba(99,102,241,0.15)" : selectedDay && isSameDay(day, selectedDay) ? "var(--bg-glass)" : "transparent",
                        border: isCurrentDay ? "1px solid var(--accent-primary)" : "1px solid transparent",
                        transition: "all 0.15s" }}
                      onMouseEnter={e => { if (!isCurrentDay) e.currentTarget.style.background = "var(--bg-glass)"; }}
                      onMouseLeave={e => { if (!isCurrentDay && !(selectedDay && isSameDay(day, selectedDay))) e.currentTarget.style.background = "transparent"; }}>
                      <div style={{ fontSize: 13, fontWeight: isCurrentDay ? 800 : 500, color: isCurrentDay ? "var(--accent-primary)" : "var(--text-secondary)", marginBottom: 4 }}>
                        {day.getDate()}
                      </div>
                      <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
                        {dayEvents.slice(0, 2).map(ev => (
                          <div key={ev.id} style={{ fontSize: 9, fontWeight: 600, padding: "1px 4px", borderRadius: 3,
                            background: EVENT_CONFIG[ev.type].bg, color: EVENT_CONFIG[ev.type].color,
                            overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                            {ev.title}
                          </div>
                        ))}
                        {dayEvents.length > 2 && (
                          <div style={{ fontSize: 9, color: "var(--text-muted)" }}>+{dayEvents.length - 2} lagi</div>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Legend */}
          <div style={{ display: "flex", gap: 12, marginTop: 16, flexWrap: "wrap" }}>
            {Object.entries(EVENT_CONFIG).map(([key, cfg]) => (
              <div key={key} style={{ display: "flex", alignItems: "center", gap: 5, fontSize: 11 }}>
                <div style={{ width: 10, height: 10, borderRadius: 2, background: cfg.color }} />
                <span style={{ color: "var(--text-muted)" }}>{cfg.label}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Event list */}
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          {/* Selected day events */}
          {selectedDay && (
            <div className="glass-card" style={{ padding: 20 }}>
              <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 12, color: "var(--accent-primary)" }}>
                {format(selectedDay, "EEEE, dd MMMM", { locale: idLocale })}
              </div>
              {getEventsForDay(selectedDay).length === 0 ? (
                <div style={{ fontSize: 13, color: "var(--text-muted)", textAlign: "center", padding: "16px 0" }}>Tidak ada event</div>
              ) : (
                getEventsForDay(selectedDay).map(ev => (
                  <div key={ev.id} style={{ padding: "10px 12px", borderRadius: 8,
                    background: EVENT_CONFIG[ev.type].bg, marginBottom: 8 }}>
                    <div style={{ fontSize: 13, fontWeight: 600, color: EVENT_CONFIG[ev.type].color }}>{ev.title}</div>
                    {ev.description && <div style={{ fontSize: 12, color: "var(--text-muted)", marginTop: 2 }}>{ev.description}</div>}
                  </div>
                ))
              )}
            </div>
          )}

          {/* Upcoming events */}
          <div className="glass-card" style={{ padding: 20 }}>
            <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 16 }}>Semua Event</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {sortedEvents.map(ev => (
                <div key={ev.id} style={{ display: "flex", alignItems: "flex-start", gap: 10, padding: "10px 12px",
                  background: "var(--bg-glass)", borderRadius: 10, position: "relative" }}>
                  <div style={{ width: 4, alignSelf: "stretch", borderRadius: 2, background: EVENT_CONFIG[ev.type].color, flexShrink: 0 }} />
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: 13, fontWeight: 600, marginBottom: 2 }}>{ev.title}</div>
                    <div style={{ fontSize: 11, color: "var(--text-muted)" }}>
                      {format(new Date(ev.startDate), "dd MMM", { locale: idLocale })}
                      {ev.startDate !== ev.endDate && ` – ${format(new Date(ev.endDate), "dd MMM yyyy", { locale: idLocale })}`}
                    </div>
                    <span style={{ fontSize: 10, padding: "1px 6px", borderRadius: 10,
                      background: EVENT_CONFIG[ev.type].bg, color: EVENT_CONFIG[ev.type].color }}>
                      {EVENT_CONFIG[ev.type].label}
                    </span>
                  </div>
                </div>
              ))}
              {sortedEvents.length === 0 && (
                <div style={{ textAlign: "center", color: "var(--text-muted)", fontSize: 13, padding: "16px 0" }}>Belum ada event</div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";
import { useStore } from "@/lib/store";
import { useState, useEffect } from "react";
import { Clock, BookOpen, CheckCircle, AlertCircle, Calendar } from "lucide-react";
import { v4 as uuidv4 } from "uuid";
import { Student } from "@/lib/types";

export default function SiswaMapelPage() {
  const { currentUser, schedules, teachers, subjectRecords, addSubjectRecord, updateSubjectRecord, students } = useStore();
  const [currentTime, setCurrentTime] = useState("");
  const [currentDay, setCurrentDay] = useState("");
  const [activeSchedule, setActiveSchedule] = useState<any>(null);
  const [hasAbsented, setHasAbsented] = useState(false);

  const student = currentUser as Student;
  const todayStr = new Date().toISOString().split("T")[0];

  useEffect(() => {
    const updateClock = () => {
      const now = new Date();
      const hours = String(now.getHours()).padStart(2, '0');
      const minutes = String(now.getMinutes()).padStart(2, '0');
      setCurrentTime(`${hours}:${minutes}`);

      const days = ["Minggu", "Senin", "Selasa", "Rabu", "Kamis", "Jumat", "Sabtu"];
      setCurrentDay(days[now.getDay()]);
    };

    updateClock();
    const interval = setInterval(updateClock, 60000); // Check every minute
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (!student || !currentDay) return;

    // Simulate "08:45" mapping to active schedule
    const active = schedules.find(s => {
      return s.kelas === student.kelas && s.day === currentDay && s.startTime <= currentTime && s.endTime >= currentTime;
    });

    // If testing outside school hours, maybe just pick the first schedule of the day
    // Uncomment this for easy testing if needed:
    // const active = schedules.find(s => s.kelas === student.kelas && s.day === currentDay);

    setActiveSchedule(active || null);

    if (active) {
      // Check if student already checked in for this subject today
      const existingRecord = subjectRecords.find(r => 
        r.date === todayStr && 
        r.subjectName === active.subjectName && 
        r.kelas === active.kelas && 
        r.teacherId === active.teacherId
      );

      if (existingRecord && existingRecord.presentStudentIds.includes(student.id)) {
        setHasAbsented(true);
      } else {
        setHasAbsented(false);
      }
    }
  }, [student, currentDay, currentTime, schedules, subjectRecords, todayStr]);

  const getTeacherName = (id: string) => teachers.find(t => t.id === id)?.name || "Unknown";

  const handleAbsenMapel = () => {
    if (!activeSchedule) return;

    const existingRecord = subjectRecords.find(r => 
      r.date === todayStr && 
      r.subjectName === activeSchedule.subjectName && 
      r.kelas === activeSchedule.kelas && 
      r.teacherId === activeSchedule.teacherId
    );

    if (existingRecord) {
      updateSubjectRecord(existingRecord.id, {
        presentStudentIds: [...new Set([...existingRecord.presentStudentIds, student.id])],
        absentStudentIds: existingRecord.absentStudentIds.filter(id => id !== student.id)
      });
    } else {
      // Create new record for the day
      const classStudents = students.filter(s => s.kelas === student.kelas).map(s => s.id);
      addSubjectRecord({
        id: uuidv4(),
        subjectName: activeSchedule.subjectName,
        teacherId: activeSchedule.teacherId,
        kelas: activeSchedule.kelas,
        date: todayStr,
        session: 1, // simplified
        presentStudentIds: [student.id],
        absentStudentIds: classStudents.filter(id => id !== student.id),
        createdAt: new Date().toISOString()
      });
    }

    setHasAbsented(true);
    alert(`Berhasil absen untuk mata pelajaran ${activeSchedule.subjectName}!`);
  };

  if (!student) return null;

  return (
    <div className="animate-fadeIn">
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 24, flexWrap: "wrap", gap: 16 }}>
        <div>
          <h1 style={{ fontSize: 24, fontWeight: 800 }}>Absensi Mata Pelajaran</h1>
          <p style={{ color: "var(--text-muted)", fontSize: 14 }}>Konfirmasi kehadiran Anda di jam pelajaran saat ini.</p>
        </div>
        <div style={{ background: "var(--bg-secondary)", padding: "8px 16px", borderRadius: 12, border: "1px solid var(--border-glass)", display: "flex", alignItems: "center", gap: 12 }}>
          <Clock size={16} color="var(--text-secondary)" />
          <span style={{ fontWeight: 600, fontFamily: "monospace", fontSize: 16 }}>{currentTime}</span>
          <span style={{ color: "var(--text-muted)", fontSize: 13 }}>{currentDay}</span>
        </div>
      </div>

      {!activeSchedule ? (
        <div className="glass-card" style={{ padding: "48px 24px", textAlign: "center" }}>
          <div style={{ width: 64, height: 64, borderRadius: "50%", background: "var(--bg-secondary)", display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 16px" }}>
            <Calendar size={32} color="var(--text-muted)" />
          </div>
          <h2 style={{ fontSize: 18, fontWeight: 600, marginBottom: 8 }}>Tidak Ada Kelas Saat Ini</h2>
          <p style={{ color: "var(--text-muted)", fontSize: 14 }}>Anda tidak memiliki jadwal mata pelajaran pada jam {currentTime} ini.</p>
        </div>
      ) : (
        <div className="glass-card" style={{ padding: 32, display: "flex", flexDirection: "column", alignItems: "center", textAlign: "center", maxWidth: 500, margin: "0 auto" }}>
          <div style={{ width: 80, height: 80, borderRadius: 24, background: "var(--gradient-primary)", display: "flex", alignItems: "center", justifyContent: "center", marginBottom: 20, boxShadow: "0 10px 20px rgba(99,102,241,0.2)" }}>
            <BookOpen size={40} color="white" />
          </div>
          <h2 style={{ fontSize: 24, fontWeight: 800, marginBottom: 4 }}>{activeSchedule.subjectName}</h2>
          <p style={{ color: "var(--text-muted)", fontSize: 15, marginBottom: 24 }}>Guru: {getTeacherName(activeSchedule.teacherId)}</p>

          <div style={{ background: "var(--bg-secondary)", padding: "12px 24px", borderRadius: 12, border: "1px solid var(--border-glass)", marginBottom: 32, width: "100%" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
              <span style={{ color: "var(--text-secondary)", fontSize: 13 }}>Kelas</span>
              <span style={{ fontWeight: 600 }}>{activeSchedule.kelas}</span>
            </div>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <span style={{ color: "var(--text-secondary)", fontSize: 13 }}>Jam Pelajaran</span>
              <span style={{ fontWeight: 600 }}>{activeSchedule.startTime} - {activeSchedule.endTime}</span>
            </div>
          </div>

          {hasAbsented ? (
            <div style={{ display: "flex", alignItems: "center", gap: 10, background: "rgba(34,197,94,0.1)", color: "#22c55e", padding: "16px 32px", borderRadius: 100, fontWeight: 600, width: "100%", justifyContent: "center" }}>
              <CheckCircle size={20} />
              Anda sudah absen hadir
            </div>
          ) : (
            <button onClick={handleAbsenMapel} className="btn-primary" style={{ width: "100%", padding: 16, fontSize: 16, borderRadius: 100 }}>
              Konfirmasi Kehadiran Sekarang
            </button>
          )}
        </div>
      )}
    </div>
  );
}

