"use client";
import { useStore } from "@/lib/store";
import { useCallback, useEffect, useMemo, useState } from "react";
import { format } from "date-fns";
import { id as idLocale } from "date-fns/locale";
import {
  CheckCircle, Clock, UserX, TrendingUp, Calendar, BarChart3, FileText,
} from "lucide-react";
import {
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from "recharts";
import StatusBadge from "@/components/StatusBadge";
import Link from "next/link";
import { AttendanceRecord } from "@/lib/types";

// Komponen Utama: Halaman Dashboard Siswa
// Menampilkan ringkasan kehadiran pribadi, grafik 14 hari terakhir, dan riwayat absen terbaru
export default function SiswaDashboard() {
  // Mengambil state dan fungsi dari global store
  const { currentUser, getStudentAttendance } = useStore();
  // State untuk menyimpan data absen siswa yang sedang login
  const [records, setRecords] = useState<AttendanceRecord[]>([]); 
  const [mounted, setMounted] = useState(false);

  // Effect untuk memuat data absensi siswa saat komponen di-render
  useEffect(() => {
    if (currentUser) {
      setRecords(getStudentAttendance(currentUser.id));
    }
    setMounted(true);
  }, [currentUser, getStudentAttendance]);

  const today = new Date().toISOString().split("T")[0];

  // Mengkalkulasi statistik kehadiran secara efisien menggunakan useMemo (menghindari render ulang yang tidak perlu)
  const stats = useMemo(() => {
    // Mencari data absen khusus hari ini
    const todayRecord = records.find((r) => r.date === today);
    const total  = records.length;
    const hadir  = records.filter((r) => r.status === "hadir").length;
    const telat  = records.filter((r) => r.status === "terlambat").length;
    const absen  = records.filter((r) => r.status === "tidak_hadir").length;
    const rate   = total > 0 ? Math.round(((hadir + telat) / total) * 100) : 0;
    return { todayRecord, total, hadir, telat, absen, rate };
  }, [records, today]);

  // Menyiapkan data untuk grafik garis (tren kehadiran 14 hari terakhir)
  const chartData = useMemo(() => {
    // Membangun Map berdasarkan tanggal untuk pencarian O(1) yang cepat
    const recordMap = new Map(records.map((r) => [r.date, r]));
    const data = [];
    for (let i = 13; i >= 0; i--) {
      const d = new Date(); d.setDate(d.getDate() - i);
      const ds = d.toISOString().split("T")[0];
      const rec = recordMap.get(ds);
      data.push({
        day: format(d, "dd/MM"),
        status: rec ? (rec.status === "hadir" ? 1 : rec.status === "terlambat" ? 0.5 : 0) : null,
      });
    }
    return data;
  }, [records]);

  if (!currentUser || !mounted) return null;

  const { todayRecord, hadir, telat, absen, rate } = stats;

  return (
    <div className="animate-fadeIn">
      <div style={{ marginBottom: 28 }}>
        <h1 style={{ fontSize: 26, fontWeight: 800 }}>
          Selamat Datang, {currentUser.name.split(" ")[0]} 👋
        </h1>
        <p style={{ color: "var(--text-muted)", fontSize: 14 }}>
          {format(new Date(), "EEEE, dd MMMM yyyy", { locale: idLocale })}
        </p>
      </div>

      {/* Today status card - Kartu dinamis yang berubah warna berdasarkan status absen hari ini */}
      <div className="glass-card" style={{ padding: 24, marginBottom: 24,
        background: todayRecord
          ? todayRecord.status === "hadir" ? "linear-gradient(135deg,rgba(16,185,129,0.12),rgba(5,150,105,0.06))"
            : todayRecord.status === "terlambat" ? "linear-gradient(135deg,rgba(245,158,11,0.12),rgba(217,119,6,0.06))"
            : "linear-gradient(135deg,rgba(239,68,68,0.12),rgba(220,38,38,0.06))"
          : "linear-gradient(135deg,rgba(99,102,241,0.12),rgba(139,92,246,0.06))",
        border: todayRecord
          ? todayRecord.status === "hadir" ? "1px solid rgba(16,185,129,0.25)"
            : todayRecord.status === "terlambat" ? "1px solid rgba(245,158,11,0.25)"
            : "1px solid rgba(239,68,68,0.25)"
          : "1px solid rgba(99,102,241,0.25)" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 16 }}>
          <div>
            <div style={{ fontSize: 13, color: "var(--text-muted)", marginBottom: 6 }}>Status Kehadiran Hari Ini</div>
            {todayRecord ? (
              <>
                <StatusBadge status={todayRecord.status} />
                {todayRecord.checkIn && (
                  <div style={{ fontSize: 13, color: "var(--text-secondary)", marginTop: 8 }}>
                    Check-in: <strong>{todayRecord.checkIn.time}</strong>
                    {todayRecord.checkOut && <> &nbsp;| Check-out: <strong>{todayRecord.checkOut.time}</strong></>}
                  </div>
                )}
              </>
            ) : (
              <div style={{ fontSize: 20, fontWeight: 700, color: "var(--accent-primary)", marginTop: 4 }}>
                Belum Absen
              </div>
            )}
          </div>
          {!todayRecord && (
            <Link href="/dashboard/siswa/absensi" className="btn-primary">
              Lakukan Absensi Sekarang →
            </Link>
          )}
          {todayRecord && !todayRecord.checkOut && (
            <Link href="/dashboard/siswa/absensi" className="btn-secondary">
              Check-Out →
            </Link>
          )}
        </div>
      </div>

      {/* Stats - Kartu ringkasan jumlah hadir, terlambat, alpa, dan persentase keseluruhan */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(160px,1fr))", gap: 16, marginBottom: 24 }}>
        {[
          { label: "Hadir", value: hadir,  icon: CheckCircle, color: "#10b981", type: "success" },
          { label: "Terlambat", value: telat, icon: Clock,   color: "#f59e0b", type: "warning" },
          { label: "Tidak Hadir", value: absen,icon: UserX,  color: "#ef4444", type: "danger"  },
          { label: "Tingkat Hadir", value: `${rate}%`, icon: TrendingUp, color: "#6366f1", type: "primary" },
        ].map((card) => (
          <div key={card.label} className={`stat-card ${card.type}`}>
            <card.icon size={20} color={card.color} style={{ marginBottom: 10 }} />
            <div style={{ fontSize: 28, fontWeight: 800 }}>{card.value}</div>
            <div style={{ fontSize: 12, color: "var(--text-muted)", marginTop: 4 }}>{card.label}</div>
          </div>
        ))}
      </div>

      {/* Chart - Grafik garis yang memvisualisasikan kehadiran 14 hari terakhir */}
      <div className="glass-card" style={{ padding: 24, marginBottom: 24 }}>
        <div style={{ fontSize: 15, fontWeight: 700, marginBottom: 16, display: "flex", alignItems: "center", gap: 8 }}>
          <BarChart3 size={18} color="var(--accent-primary)" /> Kehadiran 14 Hari Terakhir
        </div>
        <ResponsiveContainer width="100%" height={160}>
          <LineChart data={chartData}>
            <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" />
            <XAxis dataKey="day" tick={{ fill: "var(--text-muted)", fontSize: 11 }} axisLine={false} tickLine={false} />
            <YAxis hide domain={[0, 1]} />
            <Tooltip contentStyle={{ background: "#0f1629", border: "1px solid var(--border-glass)", borderRadius: 10 }}
              formatter={(val) => {
                const n = typeof val === "number" ? val : null;
                return n === 1 ? "Hadir" : n === 0.5 ? "Terlambat" : "Tidak Hadir";
              }} />
            <Line type="monotone" dataKey="status" stroke="#6366f1" strokeWidth={2} dot={{ fill: "#6366f1", r: 4 }} connectNulls />
          </LineChart>
        </ResponsiveContainer>
      </div>

      {/* Recent records - Tabel yang menampilkan 10 riwayat absensi paling baru */}
      <div className="glass-card" style={{ padding: 24 }}>
        <div style={{ fontSize: 15, fontWeight: 700, marginBottom: 16, display: "flex", alignItems: "center", gap: 8, justifyContent: "space-between" }}>
          <span style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <Calendar size={18} color="var(--accent-primary)" /> Riwayat Absensi Terbaru
          </span>
          {records.length > 10 && (
            <span style={{ fontSize: 12, color: "var(--text-muted)", fontWeight: 400 }}>
              Menampilkan 10 dari {records.length} data
            </span>
          )}
        </div>
        <div style={{ overflowX: "auto" }}>
          <table className="data-table">
            <thead>
              <tr><th>Tanggal</th><th>Status</th><th>Jam Masuk</th><th>Jam Keluar</th><th>Verifikasi</th></tr>
            </thead>
            <tbody>
              {records.slice(0, 10).map((r) => (
                <tr key={r.id}>
                  <td>{format(new Date(r.date), "EEE, dd MMM yyyy", { locale: idLocale })}</td>
                  <td><StatusBadge status={r.status} /></td>
                  <td>{r.checkIn?.time ?? "–"}</td>
                  <td>{r.checkOut?.time ?? "–"}</td>
                  <td style={{ fontSize: 12 }}>
                    {r.checkIn
                      ? <span style={{ color: "#10b981" }}>✓ Wajah & GPS</span>
                      : <span style={{ color: "var(--text-muted)" }}>–</span>}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

"use client";
import { useStore } from "@/lib/store";
import { useState, useEffect } from "react";
import { Megaphone, Bell, AlertTriangle, Info, Calendar } from "lucide-react";
import { AnnouncementPriority } from "@/lib/types";
import { format } from "date-fns";
import { id as idLocale } from "date-fns/locale";

const PRIORITY_CONFIG: Record<AnnouncementPriority, { label: string; color: string; bg: string; icon: React.ElementType }> = {
  normal:  { label: "Normal",  color: "#3b82f6", bg: "rgba(59,130,246,0.08)",  icon: Info },
  penting: { label: "Penting", color: "#f59e0b", bg: "rgba(245,158,11,0.08)",  icon: Bell },
  darurat: { label: "Darurat", color: "#ef4444", bg: "rgba(239,68,68,0.08)",   icon: AlertTriangle },
};

export default function SiswaPengumumanPage() {
  const { currentUser, getAnnouncementsForUser } = useStore();
  const [mounted, setMounted] = useState(false);

  // eslint-disable-next-line react-hooks/set-state-in-effect
  // eslint-disable-next-line react-hooks/set-state-in-effect
  useEffect(() => setMounted(true), []);
  if (!currentUser || !mounted) return null;

  const student = currentUser as import("@/lib/types").Student;
  const announcements = getAnnouncementsForUser(currentUser.role, student.kelas)
    .sort((a, b) => new Date(b.publishedAt).getTime() - new Date(a.publishedAt).getTime());

  return (
    <div className="animate-fadeIn">
      <div style={{ marginBottom: 28 }}>
        <h1 style={{ fontSize: 26, fontWeight: 800, marginBottom: 4, display: "flex", alignItems: "center", gap: 10 }}>
          <Megaphone size={24} color="var(--accent-primary)" /> Pengumuman Sekolah
        </h1>
        <p style={{ color: "var(--text-muted)", fontSize: 14 }}>Informasi dan pengumuman resmi dari sekolah.</p>
      </div>
      {announcements.length === 0 ? (
        <div className="glass-card" style={{ padding: 64, textAlign: "center", color: "var(--text-muted)" }}>
          <Megaphone size={56} style={{ margin: "0 auto 16px", opacity: 0.3 }} />
          <div style={{ fontSize: 16, fontWeight: 600 }}>Belum ada pengumuman</div>
        </div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          {announcements.map(ann => {
            const cfg = PRIORITY_CONFIG[ann.priority];
            const Icon = cfg.icon;
            return (
              <div key={ann.id} className="glass-card" style={{ padding: 24, borderLeft: `4px solid ${cfg.color}` }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10, flexWrap: "wrap" }}>
                  <span style={{ display: "flex", alignItems: "center", gap: 5, fontSize: 12, fontWeight: 600,
                    padding: "3px 10px", borderRadius: 12, background: cfg.bg, color: cfg.color }}>
                    <Icon size={12} /> {cfg.label}
                  </span>
                  <div style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 12, color: "var(--text-muted)" }}>
                    <Calendar size={12} />
                    {format(new Date(ann.publishedAt), "EEEE, dd MMMM yyyy", { locale: idLocale })}
                  </div>
                </div>
                <h2 style={{ fontSize: 17, fontWeight: 700, marginBottom: 10 }}>{ann.title}</h2>
                <p style={{ fontSize: 14, color: "var(--text-secondary)", lineHeight: 1.7 }}>{ann.content}</p>
                <div style={{ marginTop: 12, fontSize: 12, color: "var(--text-muted)" }}>Dari: {ann.authorName}</div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

"use client";
import { useStore } from "@/lib/store";
import { useState, useRef, useEffect, useCallback } from "react";
import { Camera, UserCheck, Loader2, CheckCircle, RefreshCcw } from "lucide-react";
import { loadFaceModels, detectFaceDescriptor, drawFaceDetection } from "@/lib/faceRecognition";
import Toast, { ToastType } from "@/components/Toast";

interface ToastState { message: string; type: ToastType }

export default function SiswaProfilPage() {
  const { currentUser, updateStudent } = useStore();
  const student = currentUser as import("@/lib/types").Student;

  const videoRef  = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const rafRef    = useRef<number>(0);

  const [cameraOn, setCameraOn]   = useState(false);
  const [loading, setLoading]     = useState(false);
  const [registered, setRegistered] = useState(false);
  const [modelsReady, setModelsReady] = useState(false);
  const [toast, setToast]         = useState<ToastState | null>(null);

  useEffect(() => {
    loadFaceModels().then(() => setModelsReady(true));
  }, []);

  const startCamera = useCallback(async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: "user" } });
      streamRef.current = stream;
      setCameraOn(true);

      setTimeout(async () => {
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          await videoRef.current.play();

          const loop = async () => {
            if (videoRef.current && canvasRef.current && videoRef.current.readyState >= 2 && videoRef.current.videoWidth > 0) {
              try {
                await drawFaceDetection(videoRef.current, canvasRef.current);
              } catch (err) {}
            }
            rafRef.current = requestAnimationFrame(loop);
          };
          rafRef.current = requestAnimationFrame(loop);
        }
      }, 100);
    } catch {
      setToast({ message: "Tidak bisa mengakses kamera", type: "error" });
    }
  }, []);

  const stopCamera = useCallback(() => {
    cancelAnimationFrame(rafRef.current);
    streamRef.current?.getTracks().forEach((t) => t.stop());
    setCameraOn(false);
  }, []);

  const registerFace = async () => {
    if (!videoRef.current || !modelsReady) return;
    setLoading(true);
    const descriptor = await detectFaceDescriptor(videoRef.current);
    if (!descriptor) {
      setToast({ message: "Wajah tidak terdeteksi. Posisikan wajah di tengah kamera.", type: "error" });
      setLoading(false);
      return;
    }
    updateStudent(currentUser!.id, { faceDescriptor: Array.from(descriptor) });
    setRegistered(true);
    setToast({ message: "Face ID berhasil didaftarkan! Sekarang Anda bisa absen dengan wajah.", type: "success" });
    stopCamera();
    setLoading(false);
  };

  if (!student) return null;

  const hasFaceId = student.faceDescriptor && student.faceDescriptor.length > 0;

  return (
    <div className="animate-fadeIn" style={{ maxWidth: 600, margin: "0 auto" }}>
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <h1 style={{ fontSize: 24, fontWeight: 800, marginBottom: 24 }}>Profil Saya</h1>

      {/* Profile card */}
      <div className="glass-card" style={{ padding: 28, marginBottom: 24 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 20, marginBottom: 24, flexWrap: "wrap" }}>
          <div style={{ width: 72, height: 72, borderRadius: "50%", background: "var(--gradient-primary)",
            display: "flex", alignItems: "center", justifyContent: "center",
            fontSize: 28, fontWeight: 800, color: "white", flexShrink: 0 }}>
            {student.name.charAt(0)}
          </div>
          <div>
            <div style={{ fontSize: 20, fontWeight: 700 }}>{student.name}</div>
            <div style={{ color: "var(--text-muted)", fontSize: 14 }}>{student.username}</div>
            <div style={{ display: "flex", gap: 8, marginTop: 6, flexWrap: "wrap" }}>
              <span className="badge badge-purple">{student.kelas}</span>
              <span className="badge badge-info">{student.jurusan}</span>
            </div>
          </div>
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
          {[
            { label: "NISN",   value: student.nisn },
            { label: "Kelas",  value: student.kelas },
            { label: "Jurusan",value: student.jurusan },
            { label: "Telepon",value: student.phone ?? "–" },
          ].map((f) => (
            <div key={f.label} style={{ background: "var(--bg-glass)", borderRadius: "var(--radius-md)", padding: "12px 16px" }}>
              <div style={{ fontSize: 11, color: "var(--text-muted)", marginBottom: 4 }}>{f.label}</div>
              <div style={{ fontSize: 14, fontWeight: 600 }}>{f.value}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Face ID registration */}
      <div className="glass-card" style={{ padding: 28 }}>
        <div style={{ fontSize: 16, fontWeight: 700, marginBottom: 6, display: "flex", alignItems: "center", gap: 8 }}>
          <Camera size={18} color="var(--accent-primary)" /> Pendaftaran Face ID
        </div>
        <p style={{ color: "var(--text-muted)", fontSize: 13, marginBottom: 20, lineHeight: 1.6 }}>
          Daftarkan wajah Anda agar bisa melakukan absensi dengan verifikasi biometrik.
          Pastikan pencahayaan baik dan wajah terlihat jelas.
        </p>

        {(hasFaceId || registered) && !cameraOn && (
          <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "14px 18px",
            background: "rgba(16,185,129,0.1)", border: "1px solid rgba(16,185,129,0.25)",
            borderRadius: "var(--radius-md)", marginBottom: 16 }}>
            <CheckCircle size={20} color="#10b981" />
            <div>
              <div style={{ fontWeight: 600, color: "#10b981", fontSize: 14 }}>Face ID Terdaftar</div>
              <div style={{ fontSize: 12, color: "var(--text-muted)" }}>Wajah Anda sudah terdaftar dalam sistem</div>
            </div>
          </div>
        )}

        {cameraOn && (
          <div style={{ marginBottom: 16, position: "relative", borderRadius: "var(--radius-md)", overflow: "hidden", aspectRatio: "4/3", background: "#000" }}>
            <video ref={videoRef} autoPlay playsInline muted style={{ width: "100%", height: "100%", objectFit: "cover", transform: "scaleX(-1)" }} />
            <canvas ref={canvasRef} style={{ position: "absolute", top: 0, left: 0, width: "100%", height: "100%", transform: "scaleX(-1)" }} />
            <div style={{ position: "absolute", bottom: 12, left: "50%", transform: "translateX(-50%)",
              background: "rgba(0,0,0,0.6)", borderRadius: 20, padding: "4px 14px", fontSize: 12, color: "var(--text-muted)" }}>
              Posisikan wajah di tengah frame
            </div>
          </div>
        )}

        <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
          {!cameraOn ? (
            <button onClick={startCamera} className="btn-primary" style={{ flex: 1, justifyContent: "center" }}>
              <Camera size={15} /> {hasFaceId ? "Perbarui Face ID" : "Daftarkan Face ID"}
            </button>
          ) : (
            <>
              <button onClick={stopCamera} className="btn-secondary">
                <RefreshCcw size={14} /> Batal
              </button>
              <button onClick={registerFace} disabled={loading || !modelsReady}
                className="btn-success" style={{ flex: 1, justifyContent: "center", opacity: loading ? 0.7 : 1 }}>
                {loading ? <><Loader2 size={14} className="animate-spin" /> Mendaftarkan...</> : <><UserCheck size={14} /> Simpan Face ID</>}
              </button>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";
import { useStore } from "@/lib/store";
import { useState, useEffect } from "react";
import { Search, Download } from "lucide-react";
import StatusBadge from "@/components/StatusBadge";
import { exportToExcel, exportToPDF } from "@/lib/exportUtils";
import { format } from "date-fns";
import { id as idLocale } from "date-fns/locale";

export default function SiswaRiwayatPage() {
  const { currentUser, getStudentAttendance } = useStore();
  const [statusFilter, setStatusFilter] = useState("all");
  const [currentPage, setCurrentPage] = useState(1);

  if (!currentUser) return null;
  const records = getStudentAttendance(currentUser.id);

  const filtered = records.filter((r) =>
    statusFilter === "all" || r.status === statusFilter
  );

  const ITEMS_PER_PAGE = 20;

  const totalPages = Math.max(1, Math.ceil(filtered.length / ITEMS_PER_PAGE));
  const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
  const paginated = filtered.slice(startIndex, startIndex + ITEMS_PER_PAGE);

  const hadir  = records.filter((r) => r.status === "hadir").length;
  const telat  = records.filter((r) => r.status === "terlambat").length;
  const absen  = records.filter((r) => r.status === "tidak_hadir").length;
  const rate   = records.length > 0 ? Math.round(((hadir + telat) / records.length) * 100) : 0;

  return (
    <div className="animate-fadeIn">
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 24, flexWrap: "wrap", gap: 16 }}>
        <div>
          <h1 style={{ fontSize: 24, fontWeight: 800 }}>Riwayat Absensi Saya</h1>
          <p style={{ color: "var(--text-muted)", fontSize: 14 }}>{records.length} total rekord</p>
        </div>
        <div style={{ display: "flex", gap: 10 }}>
          <button onClick={() => exportToPDF(filtered)} className="btn-secondary" style={{ fontSize: 13 }}>PDF</button>
          <button onClick={() => exportToExcel(filtered)} className="btn-primary" style={{ fontSize: 13 }}>
            <Download size={14} /> Excel
          </button>
        </div>
      </div>

      {/* Summary */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(130px, 1fr))", gap: 12, marginBottom: 20 }}>
        {[
          { label: "Hadir",       value: hadir,    color: "#10b981", bg: "rgba(16,185,129,0.1)" },
          { label: "Terlambat",   value: telat,    color: "#f59e0b", bg: "rgba(245,158,11,0.1)" },
          { label: "Tidak Hadir", value: absen,    color: "#ef4444", bg: "rgba(239,68,68,0.1)" },
          { label: "Kehadiran",   value: `${rate}%`,color:"#6366f1", bg:"rgba(99,102,241,0.1)" },
        ].map((c) => (
          <div key={c.label} style={{ background: c.bg, border: `1px solid ${c.color}30`, borderRadius: "var(--radius-md)", padding: 16, textAlign: "center" }}>
            <div style={{ fontSize: 24, fontWeight: 800, color: c.color }}>{c.value}</div>
            <div style={{ fontSize: 11, color: "var(--text-muted)", marginTop: 4 }}>{c.label}</div>
          </div>
        ))}
      </div>

      {/* Filter */}
      <div style={{ marginBottom: 16 }}>
        <select className="input-field" style={{ width: "auto" }} value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)}>
          <option value="all">Semua Status</option>
          <option value="hadir">Hadir</option>
          <option value="terlambat">Terlambat</option>
          <option value="tidak_hadir">Tidak Hadir</option>
        </select>
      </div>

      <div className="glass-card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ overflowX: "auto" }}>
          <table className="data-table">
            <thead>
              <tr><th>Tanggal</th><th>Status</th><th>Jam Masuk</th><th>Jam Keluar</th><th>Wajah</th><th>GPS</th></tr>
            </thead>
            <tbody>
              {paginated.map((r) => (
                <tr key={r.id}>
                  <td style={{ whiteSpace: "nowrap" }}>{format(new Date(r.date), "EEE, dd MMM yyyy", { locale: idLocale })}</td>
                  <td><StatusBadge status={r.status} /></td>
                  <td>{r.checkIn?.time ?? "–"}</td>
                  <td>{r.checkOut?.time ?? "–"}</td>
                  <td style={{ color: r.checkIn?.faceVerified ? "#10b981" : "var(--text-muted)", fontSize: 13 }}>
                    {r.checkIn?.faceVerified ? "✓" : "–"}
                  </td>
                  <td style={{ color: r.checkIn?.locationVerified ? "#10b981" : "var(--text-muted)", fontSize: 13 }}>
                    {r.checkIn?.locationVerified ? "✓" : "–"}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {filtered.length === 0 && (
          <div style={{ textAlign: "center", padding: "40px 0", color: "var(--text-muted)" }}>Tidak ada data</div>
        )}
        {totalPages > 1 && (
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "16px 20px", borderTop: "1px solid var(--border-glass)", flexWrap: "wrap", gap: 16 }}>
            <div style={{ fontSize: 13, color: "var(--text-muted)" }}>
              Menampilkan {startIndex + 1} - {Math.min(startIndex + ITEMS_PER_PAGE, filtered.length)} dari {filtered.length}
            </div>
            <div style={{ display: "flex", gap: 6 }}>
              <button onClick={() => setCurrentPage(Math.max(1, currentPage - 1))} disabled={currentPage === 1}
                style={{ padding: "6px 12px", borderRadius: 6, background: "var(--bg-secondary)", border: "1px solid var(--border-glass)", cursor: currentPage === 1 ? "not-allowed" : "pointer", opacity: currentPage === 1 ? 0.5 : 1, color: "var(--text-primary)" }}>
                Prev
              </button>
              <span style={{ padding: "6px 12px", fontSize: 13, display: "flex", alignItems: "center" }}>
                Hal {currentPage} / {totalPages}
              </span>
              <button onClick={() => setCurrentPage(Math.min(totalPages, currentPage + 1))} disabled={currentPage === totalPages}
                style={{ padding: "6px 12px", borderRadius: 6, background: "var(--bg-secondary)", border: "1px solid var(--border-glass)", cursor: currentPage === totalPages ? "not-allowed" : "pointer", opacity: currentPage === totalPages ? 0.5 : 1, color: "var(--text-primary)" }}>
                Next
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";
import { useStore } from "@/lib/store";
import { useState, useEffect } from "react";
import { User, TrendingUp, CheckCircle, Clock, UserX, Calendar } from "lucide-react";
import StatusBadge from "@/components/StatusBadge";
import { format } from "date-fns";
import { id as idLocale } from "date-fns/locale";
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from "recharts";

// Komponen Utama: Halaman Data Anak untuk Wali Murid
// Menampilkan profil lengkap, statistik kehadiran, dan riwayat absen dari masing-masing anak
export default function WaliAnakPage() {
  // Mengambil state global untuk informasi login, data rekam absen, orang tua, dan siswa
  const { currentUser, records, parents, students } = useStore();
  const [mounted, setMounted] = useState(false);

  // eslint-disable-next-line react-hooks/set-state-in-effect
  // eslint-disable-next-line react-hooks/set-state-in-effect
  useEffect(() => setMounted(true), []);
  if (!currentUser || !mounted) return null;

  const getStudentIds = () => {
    try {
      const wali = currentUser as import("@/lib/types").Parent;
      if (typeof wali.studentIds === "string") {
        return JSON.parse(wali.studentIds) as string[];
      }
      if (Array.isArray(wali.studentIds)) {
        return wali.studentIds;
      }
    } catch {
      return [];
    }
    return [];
  };

  const studentIds = getStudentIds();
  // Mengambil data siswa (anak) yang memiliki relasi dengan wali murid ini
  const myStudents = students.filter(s => studentIds.includes(s.id));

  return (
    <div className="animate-fadeIn">
      <div style={{ marginBottom: 28 }}>
        <h1 style={{ fontSize: 26, fontWeight: 800, marginBottom: 4 }}>Data Anak Saya</h1>
        <p style={{ color: "var(--text-muted)", fontSize: 14 }}>Informasi lengkap profil dan kehadiran anak Anda.</p>
      </div>

      {myStudents.map(student => {
        // Mengambil dan mengurutkan riwayat absen anak ini (terbaru di atas)
        const studentRecords = records.filter(r => r.studentId === student.id)
          .sort((a, b) => b.date.localeCompare(a.date));

        // Mengkalkulasi statistik kehadiran anak
        const hadir = studentRecords.filter(r => r.status === "hadir").length;
        const terlambat = studentRecords.filter(r => r.status === "terlambat").length;
        const sakit = studentRecords.filter(r => r.status === "sakit").length;
        const izin = studentRecords.filter(r => r.status === "izin").length;
        const alpa = studentRecords.filter(r => r.status === "tidak_hadir").length;
        const total = studentRecords.length;
        const rate = total > 0 ? Math.round(((hadir + terlambat) / total) * 100) : 0;

        // Menyiapkan data untuk Grafik Tren Kehadiran (14 hari terakhir)
        const chartData = [];
        for (let i = 13; i >= 0; i--) {
          const d = new Date(); d.setDate(d.getDate() - i);
          const ds = d.toISOString().split("T")[0];
          const rec = studentRecords.find(r => r.date === ds);
          chartData.push({
            day: format(d, "dd/MM"),
            status: rec ? (rec.status === "hadir" ? 1 : rec.status === "terlambat" ? 0.5 : 0) : null,
          });
        }

        // Memeriksa status absen anak hari ini
        const today = new Date().toISOString().split("T")[0];
        const todayRec = studentRecords.find(r => r.date === today);

        return (
          <div key={student.id} style={{ marginBottom: 32 }}>
            {/* Student profile card - Menampilkan foto, nama, kelas, jurusan, dan status absen hari ini */}
            <div className="glass-card" style={{ padding: 28, marginBottom: 20,
              background: "linear-gradient(135deg,rgba(99,102,241,0.08),rgba(139,92,246,0.04))", border: "1px solid rgba(99,102,241,0.2)" }}>
              <div style={{ display: "flex", alignItems: "center", gap: 20, flexWrap: "wrap" }}>
                <div style={{ width: 72, height: 72, borderRadius: "50%", background: "var(--gradient-primary)",
                  display: "flex", alignItems: "center", justifyContent: "center", fontSize: 28, fontWeight: 800, color: "white", flexShrink: 0 }}>
                  {student.name.charAt(0)}
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 22, fontWeight: 800, marginBottom: 6 }}>{student.name}</div>
                  <div style={{ display: "flex", gap: 12, flexWrap: "wrap" }}>
                    {[
                      { label: "NISN", value: student.nisn },
                      { label: "Kelas", value: student.kelas },
                      { label: "Jurusan", value: student.jurusan },
                    ].map(i => (
                      <div key={i.label} style={{ fontSize: 13, color: "var(--text-muted)" }}>
                        {i.label}: <strong style={{ color: "var(--text-primary)" }}>{i.value}</strong>
                      </div>
                    ))}
                  </div>
                </div>
                <div style={{ textAlign: "center" }}>
                  <div style={{ fontSize: 11, color: "var(--text-muted)", marginBottom: 4 }}>Status Hari Ini</div>
                  {todayRec ? <StatusBadge status={todayRec.status} /> : <span className="badge badge-danger">Belum Absen</span>}
                </div>
              </div>
            </div>

            {/* Stats - Kartu ringkasan jumlah hadir, terlambat, sakit, izin, alpa */}
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(120px,1fr))", gap: 14, marginBottom: 20 }}>
              {[
                { label: "Hadir", value: hadir, color: "#10b981", type: "success" },
                { label: "Terlambat", value: terlambat, color: "#f59e0b", type: "warning" },
                { label: "Sakit", value: sakit, color: "#3b82f6", type: "primary" },
                { label: "Izin", value: izin, color: "#8b5cf6", type: "primary" },
                { label: "Alpa", value: alpa, color: "#ef4444", type: "danger" },
                { label: "Kehadiran", value: `${rate}%`, color: rate >= 75 ? "#10b981" : "#ef4444", type: rate >= 75 ? "success" : "danger" },
              ].map(c => (
                <div key={c.label} className={`stat-card ${c.type}`} style={{ padding: 16 }}>
                  <div style={{ fontSize: 26, fontWeight: 800, color: c.color }}>{c.value}</div>
                  <div style={{ fontSize: 11, color: "var(--text-muted)", marginTop: 2 }}>{c.label}</div>
                </div>
              ))}
            </div>

            {/* Progress bar - Visualisasi tingkat kehadiran beserta peringatan jika di bawah batas minimum (75%) */}
            <div className="glass-card" style={{ padding: 20, marginBottom: 20 }}>
              <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
                <span style={{ fontSize: 14, fontWeight: 600 }}>Tingkat Kehadiran Keseluruhan</span>
                <span style={{ fontSize: 16, fontWeight: 800, color: rate >= 75 ? "#10b981" : "#ef4444" }}>{rate}%</span>
              </div>
              <div className="progress-bar">
                <div className="progress-fill" style={{ width: `${rate}%`, background: rate >= 75 ? "var(--gradient-success)" : "var(--gradient-danger)" }} />
              </div>
              {rate < 75 && (
                <div style={{ marginTop: 8, fontSize: 12, color: "#ef4444" }}>
                  ⚠️ Kehadiran di bawah 75% — batas minimum yang ditetapkan sekolah
                </div>
              )}
            </div>

            {/* Trend chart - Grafik garis visualisasi riwayat 14 hari terakhir */}
            <div className="glass-card" style={{ padding: 24, marginBottom: 20 }}>
              <div style={{ fontSize: 15, fontWeight: 700, marginBottom: 16 }}>Kehadiran 14 Hari Terakhir</div>
              <ResponsiveContainer width="100%" height={150}>
                <LineChart data={chartData}>
                  <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" />
                  <XAxis dataKey="day" tick={{ fill: "var(--text-muted)", fontSize: 11 }} axisLine={false} tickLine={false} />
                  <YAxis hide domain={[0, 1]} />
                  <Tooltip contentStyle={{ background: "#0f1629", border: "1px solid var(--border-glass)", borderRadius: 10 }}
                    formatter={(val) => {
                      const n = typeof val === "number" ? val : null;
                      return n === 1 ? "Hadir" : n === 0.5 ? "Terlambat" : "Tidak Hadir";
                    }} />
                  <Line type="monotone" dataKey="status" stroke="#6366f1" strokeWidth={2.5} dot={{ fill: "#6366f1", r: 4 }} connectNulls />
                </LineChart>
              </ResponsiveContainer>
            </div>

            {/* Recent records - Tabel riwayat absensi terbaru (maksimal 10 data) */}
            <div className="glass-card" style={{ padding: 24 }}>
              <div style={{ fontSize: 15, fontWeight: 700, marginBottom: 16, display: "flex", alignItems: "center", gap: 8 }}>
                <Calendar size={18} color="var(--accent-primary)" /> Riwayat Terbaru
              </div>
              <div style={{ overflowX: "auto" }}>
                <table className="data-table">
                  <thead>
                    <tr><th>Tanggal</th><th>Status</th><th>Jam Masuk</th><th>Jam Keluar</th><th>Verifikasi</th></tr>
                  </thead>
                  <tbody>
                    {studentRecords.slice(0, 10).map(r => (
                      <tr key={r.id}>
                        <td style={{ whiteSpace: "nowrap" }}>{format(new Date(r.date), "EEE, dd MMM yyyy", { locale: idLocale })}</td>
                        <td><StatusBadge status={r.status} /></td>
                        <td>{r.checkIn?.time ?? "–"}</td>
                        <td>{r.checkOut?.time ?? "–"}</td>
                        <td style={{ fontSize: 12 }}>
                          {r.checkIn ? <span style={{ color: "#10b981" }}>✓ Wajah & GPS</span> : <span style={{ color: "var(--text-muted)" }}>–</span>}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
}

"use client";
