        transition: "transform 0.3s ease", display: "flex", flexDirection: "column"
      }}>
        {sidebarContent}
      </aside>

      <style>{`@media(max-width:768px){.mobile-menu-btn{display:flex!important}}`}</style>
    </>
  );
}

